  WANTS = 'WANTS',
  SAVINGS = 'SAVINGS'
}

export enum Frequency {
  MONTHLY = 'MONTHLY',
  BIWEEKLY = 'BIWEEKLY',
  WEEKLY = 'WEEKLY'
}

export interface ReminderConfig {
  enabled: boolean;
  time: string; // HH:mm
  frequency: 'DAILY' | 'WEEKLY';
}

export interface Expense {
  id: string;
  amount: number;
  category: Category;
  description: string;
  date: string;
  isFixed?: boolean;
}

export interface UserProfile {
  username: string;
  income: number;
  frequency: Frequency;
  currency: string;
  streak: number;
  lastLoginDate: string;
  reminders?: ReminderConfig;
}

export interface BudgetSplit {
