      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState, useEffect } from 'react';
import { UserProfile, Expense, Category, Frequency } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { CATEGORY_COLORS, CURRENCY_SYMBOLS } from '../constants';

interface DashboardProps {
  profile: UserProfile;
  expenses: Expense[];
  onAddExpense: (amount: number, category: Category, description: string, isFixed: boolean) => void;
  isDarkMode: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ profile, expenses, onAddExpense, isDarkMode }) => {
  const [selectedCat, setSelectedCat] = useState<Category>(Category.NEEDS);
  const [timeRemaining, setTimeRemaining] = useState<string>('');
  const [progressPercent, setProgressPercent] = useState(100);

  const currentMonth = new Date().getMonth();
  const currentYear = new Date().getFullYear();

  const monthlyExpenses = expenses.filter(e => {
    const d = new Date(e.date);
    return d.getMonth() === currentMonth && d.getFullYear() === currentYear;
  });

  const totalMonthlyExpenses = monthlyExpenses.reduce((acc, curr) => acc + curr.amount, 0);
  const balance = profile.income - totalMonthlyExpenses;
  const currencySymbol = CURRENCY_SYMBOLS[profile.currency] || '$';

  const getPeriodDays = (freq: Frequency) => {
    if (freq === Frequency.WEEKLY) return 7;
    if (freq === Frequency.BIWEEKLY) return 14;
    return 30;
  };

  useEffect(() => {
    const updateCountdown = () => {
      if (!profile.lastLoginDate) return;

      const lastDate = new Date(profile.lastLoginDate);
      const today = new Date();
      const limitDays = getPeriodDays(profile.frequency);
      const limitMs = limitDays * 24 * 60 * 60 * 1000;

      const expiryTime = lastDate.getTime() + limitMs;
      const diffMs = expiryTime - today.getTime();

      if (diffMs <= 0) {
        setTimeRemaining('Expirado');
        setProgressPercent(0);
      } else {
        const days = Math.floor(diffMs / (1000 * 60 * 60 * 24));
        const hours = Math.floor((diffMs % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
        setTimeRemaining(`${days}d ${hours}h restates`);
        setProgressPercent((diffMs / limitMs) * 100);
      }
    };

    updateCountdown();
    const timer = setInterval(updateCountdown, 60000);
    return () => clearInterval(timer);
  }, [profile.lastLoginDate, profile.frequency]);

  const getCategoryTotal = (cat: Category) => 
    monthlyExpenses.filter(e => e.category === cat).reduce((acc, curr) => acc + curr.amount, 0);

  const chartData = [
    { name: 'Necesidades', value: getCategoryTotal(Category.NEEDS), color: CATEGORY_COLORS.NEEDS },
    { name: 'Deseos', value: getCategoryTotal(Category.WANTS), color: CATEGORY_COLORS.WANTS },
    { name: 'Ahorro', value: getCategoryTotal(Category.SAVINGS), color: CATEGORY_COLORS.SAVINGS },
  ].filter(d => d.value > 0);

  const handleStreakClick = () => {
    setSelectedCat(Category.SAVINGS);
    const formElement = document.getElementById('quick-expense-form');
    if (formElement) {
      formElement.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className={`p-6 rounded-3xl border shadow-sm flex flex-col justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <span className="text-slate-500 text-sm font-medium uppercase tracking-wider">Balance Mensual</span>
          <div className="flex items-end gap-2 mt-2">
            <span className="text-3xl font-bold">{currencySymbol}{balance.toLocaleString()}</span>
            <span className={`text-xs font-bold px-2 py-1 rounded-full ${balance >= 0 ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'}`}>
              {balance >= 0 ? 'Suficiente' : 'Excedido'}
            </span>
          </div>
        </div>

        <button 
          onClick={handleStreakClick}
          className={`relative p-6 rounded-3xl border shadow-sm flex flex-col justify-between transition-all group hover:scale-[1.02] text-left active:scale-95 overflow-hidden ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}
        >
          <div 
            className="absolute bottom-0 left-0 h-1 bg-orange-500/30 transition-all duration-1000"
            style={{ width: `${progressPercent}%` }}
          />
          <div className="flex justify-between items-start">
            <span className="text-slate-500 text-sm font-medium uppercase tracking-wider group-hover:text-indigo-500 transition-colors">Racha</span>
            <span className="text-[10px] font-black text-orange-500 uppercase">{timeRemaining}</span>
          </div>
          <div className="flex items-center gap-3 mt-2">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center transition-colors ${isDarkMode ? 'bg-orange-500/20' : 'bg-orange-100'} group-hover:bg-orange-500 group-hover:text-white`}>
              <span className="text-xl animate-pulse">🔥</span>
            </div>
            <div>
              <span className="text-2xl font-bold">{profile.streak} días</span>
              <p className="text-[10px] text-slate-400 font-bold uppercase">¡Pulsa para salvar!</p>
            </div>
          </div>
        </button>

        <div className={`p-6 rounded-3xl border shadow-sm flex flex-col justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <span className="text-slate-500 text-sm font-medium uppercase tracking-wider">Gastos del Mes</span>
          <span className="text-3xl font-bold text-rose-500 mt-2">{currencySymbol}{totalMonthlyExpenses.toLocaleString()}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div id="quick-expense-form" className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <h3 className="text-lg font-bold mb-4 italic uppercase tracking-tight">Nuevo Movimiento</h3>
          <QuickExpenseForm onSubmit={onAddExpense} isDarkMode={isDarkMode} preSelectedCat={selectedCat} onCatChange={setSelectedCat} currencySymbol={currencySymbol} />
        </div>

        <div className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <h3 className="text-lg font-bold mb-4 italic uppercase tracking-tight">Distribución del Mes</h3>
          <div className="h-[200px] w-full">
            {chartData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={chartData}
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                    stroke="none"
                  >
                    {chartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', backgroundColor: isDarkMode ? '#1e293b' : '#ffffff', color: isDarkMode ? '#f1f5f9' : '#0f172a' }}
                    formatter={(value: number) => `${currencySymbol}${value.toLocaleString()}`}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full text-slate-500 text-sm italic font-medium">
                Sin movimientos este mes
              </div>
            )}
          </div>
          <div className="mt-4 flex justify-around text-[10px] font-bold uppercase tracking-widest text-slate-500">
            <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full" style={{backgroundColor: CATEGORY_COLORS.NEEDS}}/> Necesidades</div>
            <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full" style={{backgroundColor: CATEGORY_COLORS.WANTS}}/> Deseos</div>
            <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full" style={{backgroundColor: CATEGORY_COLORS.SAVINGS}}/> Ahorro</div>
          </div>
        </div>
      </div>
    </div>
  );
};

const QuickExpenseForm: React.FC<{ 
  onSubmit: (a: number, c: Category, d: string, f: boolean) => void, 
  isDarkMode: boolean, 
  preSelectedCat: Category,
  onCatChange: (c: Category) => void,
  currencySymbol: string
}> = ({ onSubmit, isDarkMode, preSelectedCat, onCatChange, currencySymbol }) => {
  const [amount, setAmount] = React.useState('');
  const [desc, setDesc] = React.useState('');
  const [isFixed, setIsFixed] = React.useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !desc) return;
    onSubmit(parseFloat(amount), preSelectedCat, desc, isFixed);
    setAmount('');
    setDesc('');
    setIsFixed(false);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="grid grid-cols-2 gap-4">
        <div className="relative">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 font-bold">{currencySymbol}</span>
          <input 
            type="number" 
            placeholder="Monto" 
            required
            value={amount} 
            onChange={e => setAmount(e.target.value)}
            className={`w-full border-none rounded-xl p-3 pl-8 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors ${isDarkMode ? 'bg-slate-800 text-white placeholder-slate-500' : 'bg-slate-50 placeholder-slate-400'}`}
          />
        </div>
        <select 
          value={preSelectedCat} 
          onChange={e => onCatChange(e.target.value as Category)}
          className={`border-none rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors ${isDarkMode ? 'bg-slate-800 text-white' : 'bg-slate-50'}`}
        >
          <option value={Category.NEEDS}>Necesidad</option>
          <option value={Category.WANTS}>Deseo</option>
          <option value={Category.SAVINGS}>Ahorro</option>
        </select>
      </div>
      <input 
        type="text" 
        placeholder="Descripción (ej. Netflix, Renta...)" 
        required
        value={desc} 
        onChange={e => setDesc(e.target.value)}
        className={`w-full border-none rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors ${isDarkMode ? 'bg-slate-800 text-white placeholder-slate-500' : 'bg-slate-50 placeholder-slate-400'}`}
      />
      <div className="flex items-center gap-2 px-2">
        <input 
          type="checkbox" 
          id="isFixed" 
          checked={isFixed}
          onChange={e => setIsFixed(e.target.checked)}
          className="w-4 h-4 text-indigo-600 rounded focus:ring-indigo-500"
        />
        <label htmlFor="isFixed" className="text-xs font-bold uppercase text-slate-500 tracking-tight cursor-pointer">
          ¿Es un {preSelectedCat === Category.WANTS ? 'deseo' : 'gasto'} fijo?
        </label>
      </div>
      <button type="submit" className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg active:scale-95">
        Guardar Transacción
      </button>
    </form>
  );
};

export default Dashboard;

import React from 'react';
import { UserProfile, Expense, Category, Frequency } from '../types';
import { CATEGORY_COLORS, CATEGORY_LABELS, FREQUENCY_LABELS } from '../constants';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Legend,
  Cell
} from 'recharts';

interface BudgetDetailsProps {
  profile: UserProfile;
  expenses: Expense[];
  onDeleteExpense: (id: string) => void;
  isDarkMode: boolean;
}

const BudgetDetails: React.FC<BudgetDetailsProps> = ({ profile, expenses, onDeleteExpense, isDarkMode }) => {
  const getMonthlyIncome = () => {
    switch (profile.frequency) {
      case Frequency.WEEKLY: return profile.income * 4;
      case Frequency.BIWEEKLY: return profile.income * 2;
      default: return profile.income;
    }
  };

  const monthlyIncome = getMonthlyIncome();
  const splits = {
    [Category.NEEDS]: monthlyIncome * 0.50,
    [Category.WANTS]: monthlyIncome * 0.30,
    [Category.SAVINGS]: monthlyIncome * 0.20,
  };

  const currentMonth = new Date().getMonth();
  const currentYear = new Date().getFullYear();

  const getSpentThisMonth = (cat: Category) => 
    expenses.filter(e => {
      const d = new Date(e.date);
      return e.category === cat && d.getMonth() === currentMonth && d.getFullYear() === currentYear;
    }).reduce((acc, curr) => acc + curr.amount, 0);

  const chartData = [
    { name: 'Necesidades', Presupuesto: splits[Category.NEEDS], Gastado: getSpentThisMonth(Category.NEEDS), color: CATEGORY_COLORS.NEEDS },
    { name: 'Deseos', Presupuesto: splits[Category.WANTS], Gastado: getSpentThisMonth(Category.WANTS), color: CATEGORY_COLORS.WANTS },
    { name: 'Ahorro', Presupuesto: splits[Category.SAVINGS], Gastado: getSpentThisMonth(Category.SAVINGS), color: CATEGORY_COLORS.SAVINGS },
  ];

  const groupedExpenses = expenses.reduce((acc, exp) => {
    const date = new Date(exp.date);
    const monthYear = date.toLocaleDateString('es-ES', { month: 'long', year: 'numeric' });
    if (!acc[monthYear]) acc[monthYear] = [];
    acc[monthYear].push(exp);
    return acc;
  }, {} as Record<string, Expense[]>);

  const monthKeys = Object.keys(groupedExpenses).sort((a, b) => {
    return new Date(groupedExpenses[b][0].date).getTime() - new Date(groupedExpenses[a][0].date).getTime();
  });

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <div className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <h2 className="text-xl font-bold italic uppercase tracking-tight">Análisis del Mes Actual</h2>
        <div className="h-[300px] w-full mt-6">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} margin={{ top: 20, right: 30, left: 0, bottom: 0 }} barGap={8}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? "#1e293b" : "#f1f5f9"} />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: isDarkMode ? '#94a3b8' : '#64748b', fontSize: 12, fontWeight: 700 }} />
              <YAxis axisLine={false} tickLine={false} tick={{ fill: isDarkMode ? '#64748b' : '#94a3b8', fontSize: 10 }} />
              <Tooltip cursor={{ fill: isDarkMode ? '#1e293b' : '#f8fafc' }} contentStyle={{ borderRadius: '16px', border: 'none', backgroundColor: isDarkMode ? '#1e293b' : '#fff' }} />
              <Bar name="Límite" dataKey="Presupuesto" fill={isDarkMode ? "#334155" : "#e2e8f0"} radius={[6, 6, 0, 0]} barSize={32} />
              <Bar name="Gastado" dataKey="Gastado" radius={[6, 6, 0, 0]} barSize={32}>
                {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="space-y-4">
        <h2 className="text-xl font-bold italic uppercase tracking-tight px-2">Historial por Periodos</h2>
        {monthKeys.length === 0 ? (
          <div className={`p-10 text-center rounded-3xl border border-dashed transition-colors ${isDarkMode ? 'bg-slate-900/50 border-slate-800' : 'bg-white border-slate-200'}`}>
            <p className="text-slate-500 font-medium italic">No hay transacciones registradas todavía.</p>
          </div>
        ) : (
          monthKeys.map(month => (
            <div key={month} className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
              <h3 className="text-sm font-black uppercase tracking-widest text-indigo-500 mb-4 flex items-center gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-indigo-500"/>
                {month}
              </h3>
              <div className="space-y-2">
                {groupedExpenses[month].slice().reverse().map(exp => (
                  <div key={exp.id} className={`flex items-center justify-between p-3 rounded-xl transition-all group ${isDarkMode ? 'hover:bg-slate-800' : 'hover:bg-slate-50'}`}>
                    <div className="flex items-center gap-3">
                      <div className="w-2 h-2 rounded-full shadow-sm" style={{ backgroundColor: CATEGORY_COLORS[exp.category] }} />
                      <div>
                        <p className="text-sm font-bold flex items-center gap-2">
                          {exp.description}
                          {exp.isFixed && <span className="text-[8px] bg-slate-200 dark:bg-slate-700 text-slate-500 px-1 rounded uppercase">Fijo</span>}
                        </p>
                        <p className="text-[10px] text-slate-500 font-bold uppercase">{new Date(exp.date).toLocaleDateString()} • {CATEGORY_LABELS[exp.category]}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="text-sm font-black">-${exp.amount.toLocaleString()}</span>
                      <button onClick={() => onDeleteExpense(exp.id)} className="p-2 opacity-0 group-hover:opacity-100 text-slate-300 hover:text-rose-500 transition-all">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                        </svg>
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default BudgetDetails;

import React, { useEffect, useState, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { getFinancialAdvice } from '../services/geminiService';
import { UserProfile, Expense, SavingsGoal } from '../types';

interface LearningCenterProps {
  profile: UserProfile;
  expenses: Expense[];
  goals: SavingsGoal[];
  onUpdateGoals: (goals: SavingsGoal[]) => void;
  isDarkMode: boolean;
}

interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

const LearningCenter: React.FC<LearningCenterProps> = ({ profile, expenses, goals, onUpdateGoals, isDarkMode }) => {
  const [tips, setTips] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [showGoalForm, setShowGoalForm] = useState(false);
  const [goalName, setGoalName] = useState('');
  const [goalAmount, setGoalAmount] = useState('');

  // Chat states
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [userInput, setUserInput] = useState('');
  const [isChatting, setIsChatting] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const fetchTips = async () => {
      setLoading(true);
      const advice = await getFinancialAdvice(profile, expenses, goals);
      setTips(advice);
      setLoading(false);
    };
    fetchTips();
  }, [profile, expenses, goals]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chatMessages]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userInput.trim() || isChatting) return;

    const userText = userInput;
    setUserInput('');
    setChatMessages(prev => [...prev, { role: 'user', text: userText }]);
    setIsChatting(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const context = `Usuario: ${profile.username}. Ingreso: ${profile.income} ${profile.currency}. Gastos: ${JSON.stringify(expenses.slice(-10))}. Metas: ${JSON.stringify(goals)}.`;

      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: `Eres Zcorpion, un asistente financiero experto. Responde preguntas cortas y directas basadas en el contexto del usuario: ${context}. Sé motivador y realista.`
        }
      });

      const response = await chat.sendMessage({ message: userText });
      const botText = response.text || "Lo siento, tuve un problema analizando eso.";
      setChatMessages(prev => [...prev, { role: 'model', text: botText }]);
    } catch (err) {
      console.error(err);
      setChatMessages(prev => [...prev, { role: 'model', text: "Ocurrió un error con la conexión a la IA." }]);
    } finally {
      setIsChatting(false);
    }
  };

  const handleUpdateProgress = (id: string, amount: string) => {
    const value = parseFloat(amount);
    if (isNaN(value)) return;
    const newGoals = goals.map(g => g.id === id ? { ...g, currentAmount: g.currentAmount + value } : g);
    onUpdateGoals(newGoals);
  };

  return (
    <div className="space-y-8 pb-24 animate-in fade-in duration-500">
      {/* AI Chat Box */}
      <section className={`p-6 rounded-[2rem] border shadow-lg overflow-hidden flex flex-col h-[450px] transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <div className="flex items-center gap-3 mb-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold">ZC</div>
          <div>
            <h2 className="font-black italic uppercase text-lg leading-tight tracking-tight">Chat con Zcorpion</h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Consejos en tiempo real</p>
          </div>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto space-y-4 mb-4 pr-2 custom-scrollbar">
          {chatMessages.length === 0 && (
            <div className="text-center py-10">
              <p className="text-slate-400 text-sm italic">"¿Cómo puedo ahorrar más este mes?"<br/>"¿Es buen momento para comprar un auto?"</p>
            </div>
          )}
          {chatMessages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : (isDarkMode ? 'bg-slate-800 text-slate-200' : 'bg-slate-100 text-slate-800') + ' rounded-tl-none'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isChatting && (
            <div className="flex justify-start">
              <div className="bg-slate-100 dark:bg-slate-800 p-3 rounded-2xl rounded-tl-none animate-pulse text-xs font-bold text-slate-500 uppercase">
                Zcorpion pensando...
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleSendMessage} className="relative">
          <input 
            type="text"
            value={userInput}
            onChange={e => setUserInput(e.target.value)}
            placeholder="Pregúntale algo a Zcorpion..."
            className={`w-full p-4 pr-12 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all ${isDarkMode ? 'bg-slate-800 text-white' : 'bg-slate-50 text-slate-900'}`}
          />
          <button type="submit" disabled={isChatting} className="absolute right-3 top-1/2 -translate-y-1/2 text-indigo-500 hover:scale-110 transition-transform disabled:opacity-50">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor">
              <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
            </svg>
          </button>
        </form>
      </section>

      {/* Quick AI Tips */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {loading ? Array(3).fill(0).map((_, i) => <div key={i} className="h-40 animate-pulse rounded-3xl bg-slate-200 dark:bg-slate-800" />) : (
          tips.map((tip, idx) => (
            <div key={idx} className={`p-5 rounded-3xl border shadow-sm ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
              <h4 className="font-bold text-sm mb-1 uppercase text-indigo-500">{tip.title}</h4>
              <p className="text-xs text-slate-500 leading-relaxed">{tip.content}</p>
            </div>
          ))
        )}
      </div>

      <section className={`p-8 rounded-[2rem] border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
          <div>
            <h2 className="text-2xl font-bold italic uppercase">Tus Metas</h2>
            <p className="text-xs text-slate-500 font-bold uppercase tracking-wider">Asegura tu libertad financiera.</p>
          </div>
          <button onClick={() => setShowGoalForm(!showGoalForm)} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold text-sm hover:bg-indigo-700 transition-all shadow-lg active:scale-95">
            {showGoalForm ? 'Cerrar' : '+ Nueva Meta'}
          </button>
        </div>

        {showGoalForm && (
          <form onSubmit={(e) => {
            e.preventDefault();
            if (!goalName || !goalAmount) return;
            onUpdateGoals([...goals, { id: Math.random().toString(36).substr(2, 9), name: goalName, targetAmount: parseFloat(goalAmount), currentAmount: 0 }]);
            setGoalName(''); setGoalAmount(''); setShowGoalForm(false);
          }} className="mb-6 p-6 rounded-2xl border bg-slate-50 dark:bg-slate-800 dark:border-slate-700 animate-in slide-in-from-top duration-300">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <input type="text" placeholder="¿Qué quieres lograr?" value={goalName} onChange={e => setGoalName(e.target.value)} required className="p-3 rounded-xl dark:bg-slate-700 outline-none focus:ring-2 focus:ring-indigo-500" />
              <input type="number" placeholder="Monto total" value={goalAmount} onChange={e => setGoalAmount(e.target.value)} required className="p-3 rounded-xl dark:bg-slate-700 outline-none focus:ring-2 focus:ring-indigo-500" />
            </div>
            <button type="submit" className="mt-4 w-full bg-indigo-600 text-white py-3 rounded-xl font-bold uppercase tracking-widest text-xs">Crear Meta</button>
          </form>
        )}

        <div className="space-y-4">
          {goals.map(goal => {
            const percentage = Math.min((goal.currentAmount / goal.targetAmount) * 100, 100);
            return (
              <div key={goal.id} className="p-5 rounded-2xl border dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50">
                <div className="flex justify-between items-start mb-3">
                  <h4 className="font-black uppercase italic tracking-tighter">{goal.name}</h4>
                  <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">${goal.currentAmount.toLocaleString()} / ${goal.targetAmount.toLocaleString()}</span>
                </div>
                <div className="h-2 w-full bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden mb-4">
                  <div className="h-full bg-emerald-500 transition-all duration-1000" style={{ width: `${percentage}%` }} />
                </div>
                <div className="flex gap-2">
                  <input type="number" placeholder="Abonar..." className="flex-1 p-2 rounded-lg bg-white dark:bg-slate-800 text-sm outline-none" onKeyDown={(e) => { if (e.key === 'Enter') { handleUpdateProgress(goal.id, (e.target as HTMLInputElement).value); (e.target as HTMLInputElement).value = ''; } }} />
                  <button onClick={(e) => { const i = e.currentTarget.previousSibling as HTMLInputElement; handleUpdateProgress(goal.id, i.value); i.value = ''; }} className="bg-emerald-500 text-white px-4 py-2 rounded-lg font-bold text-[10px] uppercase">Sumar</button>
                </div>
              </div>
            );
          })}
        </div>
      </section>
    </div>
  );
};

export default LearningCenter;

import React, { useState } from 'react';
import { UserProfile, Frequency, ReminderConfig } from '../types';
import { CURRENCY_LABELS, FREQUENCY_LABELS } from '../constants';

interface SettingsProps {
  isDarkMode: boolean;
  toggleDarkMode: () => void;
  onLogout: () => void;
  profile: UserProfile;
  onUpdateProfile: (updates: Partial<UserProfile>) => void;
}

const Settings: React.FC<SettingsProps> = ({ isDarkMode, toggleDarkMode, onLogout, profile, onUpdateProfile }) => {
  const [income, setIncome] = useState(profile.income.toString());
  const [reminderConfig, setReminderConfig] = useState<ReminderConfig>(profile.reminders || {
    enabled: false,
    time: '20:00',
    frequency: 'DAILY'
  });

  const handleUpdateReminders = (updates: Partial<ReminderConfig>) => {
    const newConfig = { ...reminderConfig, ...updates };
    setReminderConfig(newConfig);
    onUpdateProfile({ reminders: newConfig });

    if (updates.enabled && Notification.permission !== 'granted') {
      Notification.requestPermission();
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 max-w-2xl mx-auto pb-24">
      <h2 className="text-3xl font-bold italic uppercase tracking-tight">Ajustes</h2>

      <div className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <h3 className="text-lg font-bold mb-6 uppercase tracking-tight italic flex items-center gap-2">
          <span className="w-1.5 h-1.5 rounded-full bg-indigo-500"/>
          Perfil Financiero
        </h3>

        <div className="space-y-5">
          <div>
            <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Nombre de Usuario</label>
            <input 
              type="text"
              value={profile.username}
              onChange={(e) => onUpdateProfile({ username: e.target.value })}
              className={`w-full p-3 rounded-xl border-none outline-none focus:ring-2 focus:ring-indigo-500 ${isDarkMode ? 'bg-slate-800' : 'bg-slate-50'}`}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Ingreso</label>
              <input 
                type="number"
                value={income}
                onChange={(e) => setIncome(e.target.value)}
                onBlur={() => onUpdateProfile({ income: parseFloat(income) || 0 })}
                className={`w-full p-3 rounded-xl border-none outline-none focus:ring-2 focus:ring-indigo-500 ${isDarkMode ? 'bg-slate-800' : 'bg-slate-50'}`}
              />
            </div>
            <div>
              <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Divisa</label>
              <select 
                value={profile.currency}
                onChange={(e) => onUpdateProfile({ currency: e.target.value })}
                className={`w-full p-3 rounded-xl border-none outline-none focus:ring-2 focus:ring-indigo-500 ${isDarkMode ? 'bg-slate-800' : 'bg-slate-50'}`}
              >
                {Object.entries(CURRENCY_LABELS).map(([code, label]) => (
                  <option key={code} value={code}>{label}</option>
                ))}
              </select>
            </div>
          </div>
        </div>
      </div>

      {/* Recordatorios Section */}
      <div className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <h3 className="text-lg font-bold mb-6 uppercase tracking-tight italic flex items-center gap-2">
          <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"/>
          Recordatorios
        </h3>

        <div className="space-y-4">
          <div className="flex items-center justify-between mb-2">
            <div>
              <p className="font-bold text-sm uppercase">Notificaciones Push</p>
              <p className="text-[10px] text-slate-500 font-bold uppercase">Alertas para registrar gastos diarios.</p>
            </div>
            <button 
              onClick={() => handleUpdateReminders({ enabled: !reminderConfig.enabled })}
              className={`w-12 h-6 rounded-full p-1 transition-colors ${reminderConfig.enabled ? 'bg-indigo-600' : 'bg-slate-300'}`}
            >
              <div className={`w-4 h-4 bg-white rounded-full transform transition-transform ${reminderConfig.enabled ? 'translate-x-6' : 'translate-x-0'}`} />
            </button>
          </div>

          {reminderConfig.enabled && (
            <div className="grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
              <div>
                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Hora de Alerta</label>
                <input 
                  type="time"
                  value={reminderConfig.time}
                  onChange={(e) => handleUpdateReminders({ time: e.target.value })}
                  className={`w-full p-3 rounded-xl border-none outline-none ${isDarkMode ? 'bg-slate-800' : 'bg-slate-50'}`}
                />
              </div>
              <div>
                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Frecuencia</label>
                <select 
                  value={reminderConfig.frequency}
                  onChange={(e) => handleUpdateReminders({ frequency: e.target.value as 'DAILY' | 'WEEKLY' })}
                  className={`w-full p-3 rounded-xl border-none outline-none ${isDarkMode ? 'bg-slate-800' : 'bg-slate-50'}`}
                >
                  <option value="DAILY">Diario</option>
                  <option value="WEEKLY">Semanal</option>
                </select>
              </div>
            </div>
          )}
        </div>
      </div>

      <div className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <h3 className="text-lg font-bold mb-4 uppercase italic">Apariencia</h3>
        <div className="flex items-center justify-between">
          <p className="font-bold text-sm uppercase">Tema Oscuro</p>
          <button onClick={toggleDarkMode} className={`w-12 h-6 rounded-full p-1 transition-colors ${isDarkMode ? 'bg-indigo-600' : 'bg-slate-300'}`}>
            <div className={`w-4 h-4 bg-white rounded-full transform transition-transform ${isDarkMode ? 'translate-x-6' : 'translate-x-0'}`} />
          </button>
        </div>
      </div>

      <button 
        onClick={onLogout}
        className="w-full bg-rose-500/10 text-rose-500 font-black uppercase tracking-widest py-4 rounded-xl hover:bg-rose-500/20 transition-all border border-rose-500/20"
      >
        Cerrar Sesión
      </button>

      <div className="text-center pt-6">
        <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest italic">zcorpion v2.0.0</p>
      </div>
    </div>
  );
};

export default Settings;

import React, { useState, useEffect } from 'react';
import { UserProfile, Expense, Frequency, Category, SavingsGoal } from './types';
import Onboarding from './components/Onboarding';
import Dashboard from './components/Dashboard';
import BudgetDetails from './components/BudgetDetails';
import LearningCenter from './components/LearningCenter';
import Settings from './components/Settings';
import { FREQUENCY_LABELS, CURRENCY_SYMBOLS } from './constants';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [goals, setGoals] = useState<SavingsGoal[]>([]);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'budget' | 'learn' | 'settings'>('dashboard');
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    return localStorage.getItem('finanza_dark_mode') === 'true';
  });

  const getPeriodDays = (freq: Frequency) => {
    if (freq === Frequency.WEEKLY) return 7;
    if (freq === Frequency.BIWEEKLY) return 14;
    return 30;
  };

  useEffect(() => {
    const savedProfile = localStorage.getItem('finanza_profile');
    const savedExpenses = localStorage.getItem('finanza_expenses');
    const savedGoals = localStorage.getItem('finanza_goals');

    if (savedProfile) {
      const parsedProfile: UserProfile = JSON.parse(savedProfile);
      if (parsedProfile.lastLoginDate) {
        const lastDate = new Date(parsedProfile.lastLoginDate);
        const today = new Date();
        const diffMs = today.getTime() - lastDate.getTime();
        const diffDays = Math.floor(diffMs / (1000 * 3600 * 24));
        const limit = getPeriodDays(parsedProfile.frequency);
        if (diffDays >= limit) parsedProfile.streak = 0;
      }
      setProfile(parsedProfile);
    }
    if (savedExpenses) setExpenses(JSON.parse(savedExpenses));
    if (savedGoals) setGoals(JSON.parse(savedGoals));
  }, []);

  useEffect(() => {
    if (profile) localStorage.setItem('finanza_profile', JSON.stringify(profile));
    if (expenses.length >= 0) localStorage.setItem('finanza_expenses', JSON.stringify(expenses));
    if (goals.length >= 0) localStorage.setItem('finanza_goals', JSON.stringify(goals));
    localStorage.setItem('finanza_dark_mode', isDarkMode.toString());
  }, [profile, expenses, goals, isDarkMode]);

  const handleOnboardingComplete = (username: string, income: number, frequency: Frequency, currency: string) => {
    const newProfile: UserProfile = {
      username,
      income,
      frequency,
      currency,
      streak: 0,
      lastLoginDate: new Date().toISOString()
    };
    setProfile(newProfile);
  };

  const addExpense = (amount: number, category: Category, description: string, isFixed: boolean) => {
    const newExpense: Expense = {
      id: Math.random().toString(36).substr(2, 9),
      amount,
      category,
      description,
      isFixed,
      date: new Date().toISOString()
    };

    setExpenses([...expenses, newExpense]);

    if (category === Category.SAVINGS && profile) {
      const today = new Date().toDateString();
      const lastSavingsDate = profile.lastLoginDate ? new Date(profile.lastLoginDate).toDateString() : "";
      let newStreak = profile.streak;
      if (today !== lastSavingsDate) newStreak += 1;
      setProfile({ ...profile, streak: newStreak, lastLoginDate: new Date().toISOString() });
    }
  };

  const deleteExpense = (id: string) => setExpenses(expenses.filter(e => e.id !== id));
  const updateGoals = (newGoals: SavingsGoal[]) => setGoals(newGoals);
  const handleUpdateProfile = (updates: Partial<UserProfile>) => { if (profile) setProfile({ ...profile, ...updates }); };

  const logout = () => {
    localStorage.clear();
    setProfile(null); setExpenses([]); setGoals([]); setActiveTab('dashboard');
  };

  if (!profile) return <Onboarding onComplete={handleOnboardingComplete} />;

  const getMonthlyEquivalent = () => {
    switch (profile.frequency) {
      case Frequency.WEEKLY: return profile.income * 4;
      case Frequency.BIWEEKLY: return profile.income * 2;
      default: return profile.income;
    }
  };

  const currencySymbol = CURRENCY_SYMBOLS[profile.currency] || '$';

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-300 ${isDarkMode ? 'dark bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <header className={`border-b sticky top-0 z-30 px-6 py-4 flex items-center justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800 shadow-xl' : 'bg-white border-slate-100 shadow-sm'}`}>
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-xs">ZC</div>
          <h1 className="text-xl font-black tracking-tight italic uppercase">ZCORPION</h1>
        </div>
        <button onClick={() => setActiveTab('settings')} className={`p-2 rounded-xl border-2 transition-all ${isDarkMode ? 'bg-slate-800 border-indigo-900' : 'bg-slate-50 border-indigo-50'} ${activeTab === 'settings' ? 'ring-2 ring-indigo-500 scale-110' : ''}`}>
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-indigo-500" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M11.49 3.17c-.38-1.56-2.6-1.56-2.98 0a1.532 1.532 0 01-2.286.948c-1.372-.836-2.942.734-2.106 2.106.54.886.061 2.042-.947 2.287-1.561.379-1.561 2.6 0 2.978a1.532 1.532 0 01.947 2.287c-.836 1.372.734 2.942 2.106 2.106a1.532 1.532 0 012.287.947c.379 1.561 2.6 1.561 2.978 0a1.533 1.533 0 012.287-.947c1.372.836 2.942-.734 2.106-2.106a1.533 1.533 0 01.947-2.287c1.561-.379 1.561-2.6 0-2.978a1.532 1.532 0 01-.947-2.287c.836-1.372-.734-2.942-2.106-2.106a1.532 1.532 0 01-2.287-.947zM10 13a3 3 0 100-6 3 3 0 000 6z" clipRule="evenodd" />
          </svg>
        </button>
      </header>

      <main className="flex-1 max-w-5xl w-full mx-auto p-4 md:p-6 mb-24">
        {activeTab !== 'settings' && (
          <div className="mb-8">
            <h2 className="text-3xl font-black italic leading-tight">Hola, {profile.username} 👋</h2>
            <div className="flex items-center gap-2 mt-1">
              <span className="text-[10px] font-black uppercase tracking-widest text-indigo-500">Plan Mensual: {currencySymbol}{getMonthlyEquivalent().toLocaleString(undefined, { maximumFractionDigits: 0 })}</span>
              <span className="w-1 h-1 rounded-full bg-slate-300"/>
              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{FREQUENCY_LABELS[profile.frequency]}</span>
            </div>
          </div>
        )}

