                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', backgroundColor: isDarkMode ? '#1e293b' : '#ffffff', color: isDarkMode ? '#f1f5f9' : '#0f172a' }}
                    formatter={(value: number) => `${currencySymbol}${value.toLocaleString()}`}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full text-slate-500 text-sm italic font-medium">
                Sin movimientos en este {periodLabel.toLowerCase()}
              </div>
            )}
          </div>
          <div className="mt-4 flex justify-around text-[10px] font-bold uppercase tracking-widest text-slate-500">
            <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full" style={{backgroundColor: CATEGORY_COLORS.NEEDS}}/> Necesidades</div>
            <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full" style={{backgroundColor: CATEGORY_COLORS.WANTS}}/> Deseos</div>
            <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full" style={{backgroundColor: CATEGORY_COLORS.SAVINGS}}/> Ahorro</div>
          </div>
        </div>
      </div>
    </div>
  );
};

const QuickExpenseForm: React.FC<{ 
  onSubmit: (a: number, c: Category, d: string, f: boolean, freq?: Frequency) => void, 
  isDarkMode: boolean, 
  preSelectedCat: Category,
  onCatChange: (c: Category) => void,
  currencySymbol: string
}> = ({ onSubmit, isDarkMode, preSelectedCat, onCatChange, currencySymbol }) => {
  const [amount, setAmount] = React.useState('');
  const [desc, setDesc] = React.useState('');
  const [isFixed, setIsFixed] = React.useState(false);
  const [frequency, setFrequency] = React.useState<Frequency>(Frequency.MONTHLY);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !desc) return;
    onSubmit(parseFloat(amount), preSelectedCat, desc, isFixed, isFixed ? frequency : undefined);
    setAmount('');
    setDesc('');
    setIsFixed(false);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="grid grid-cols-2 gap-4">
        <div className="relative">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 font-bold">{currencySymbol}</span>
          <input 
            type="number" 
            placeholder="Monto" 
            required
            value={amount} 
            onChange={e => setAmount(e.target.value)}
            className={`w-full border-none rounded-xl p-3 pl-8 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors ${isDarkMode ? 'bg-slate-800 text-white placeholder-slate-500' : 'bg-slate-50 placeholder-slate-400'}`}
          />
        </div>
        <select 
          value={preSelectedCat} 
          onChange={e => onCatChange(e.target.value as Category)}
          className={`border-none rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors ${isDarkMode ? 'bg-slate-800 text-white' : 'bg-slate-50'}`}
        >
          <option value={Category.NEEDS}>Necesidad</option>
          <option value={Category.WANTS}>Deseo</option>
          <option value={Category.SAVINGS}>Ahorro</option>
        </select>
      </div>
      <input 
        type="text" 
        placeholder="Descripción (ej. Netflix, Renta...)" 
        required
        value={desc} 
        onChange={e => setDesc(e.target.value)}
        className={`w-full border-none rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors ${isDarkMode ? 'bg-slate-800 text-white placeholder-slate-500' : 'bg-slate-50 placeholder-slate-400'}`}
      />

      <div className="flex flex-col gap-3 px-2">
        <div className="flex items-center gap-2">
          <input 
            type="checkbox" 
            id="isFixed" 
            checked={isFixed}
            onChange={e => setIsFixed(e.target.checked)}
            className="w-4 h-4 text-indigo-600 rounded focus:ring-indigo-500"
          />
          <label htmlFor="isFixed" className="text-xs font-bold uppercase text-slate-500 tracking-tight cursor-pointer">
            ¿Es un {preSelectedCat === Category.WANTS ? 'deseo' : 'gasto'} fijo?
          </label>
        </div>

        {isFixed && (
          <div className="animate-in slide-in-from-left-2 duration-300">
             <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">Frecuencia del Gasto Fijo</label>
             <div className="grid grid-cols-3 gap-2">
                {Object.entries(FREQUENCY_LABELS).map(([key, label]) => (
                  <button
                    key={key}
                    type="button"
                    onClick={() => setFrequency(key as Frequency)}
                    className={`py-2 text-[10px] font-black uppercase tracking-tighter rounded-lg border transition-all ${
                      frequency === key
                        ? 'bg-indigo-600 text-white border-indigo-600 shadow-md'
                        : isDarkMode ? 'bg-slate-800 text-slate-400 border-slate-700' : 'bg-white text-slate-600 border-slate-200'
                    }`}
                  >
                    {label}
                  </button>
                ))}
             </div>
          </div>
        )}
      </div>

      <button type="submit" className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg active:scale-95">
        Guardar Transacción
      </button>
    </form>
  );
};

export default Dashboard;

import React from 'react';
import { UserProfile, Expense, Category, Frequency } from '../types';
import { CATEGORY_COLORS, CATEGORY_LABELS, CURRENCY_SYMBOLS, FREQUENCY_LABELS } from '../constants';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell
} from 'recharts';

interface BudgetDetailsProps {
  profile: UserProfile;
  expenses: Expense[];
  onDeleteExpense: (id: string) => void;
  isDarkMode: boolean;
}

const BudgetDetails: React.FC<BudgetDetailsProps> = ({ profile, expenses, onDeleteExpense, isDarkMode }) => {
  const currencySymbol = CURRENCY_SYMBOLS[profile.currency] || '$';

  const getMonthlyIncome = () => {
    switch (profile.frequency) {
      case Frequency.WEEKLY: return profile.income * 4;
      case Frequency.BIWEEKLY: return profile.income * 2;
      default: return profile.income;
    }
  };

  const monthlyIncome = getMonthlyIncome();
  const splits = {
    [Category.NEEDS]: monthlyIncome * 0.50,
    [Category.WANTS]: monthlyIncome * 0.30,
    [Category.SAVINGS]: monthlyIncome * 0.20,
  };

  const currentMonth = new Date().getMonth();
  const currentYear = new Date().getFullYear();

  const getSpentThisMonth = (cat: Category) => 
    expenses.filter(e => {
      const d = new Date(e.date);
      return e.category === cat && d.getMonth() === currentMonth && d.getFullYear() === currentYear;
    }).reduce((acc, curr) => acc + curr.amount, 0);

  const chartData = [
    { name: 'Necesidades', Presupuesto: splits[Category.NEEDS], Gastado: getSpentThisMonth(Category.NEEDS), color: CATEGORY_COLORS.NEEDS },
    { name: 'Deseos', Presupuesto: splits[Category.WANTS], Gastado: getSpentThisMonth(Category.WANTS), color: CATEGORY_COLORS.WANTS },
    { name: 'Ahorro', Presupuesto: splits[Category.SAVINGS], Gastado: getSpentThisMonth(Category.SAVINGS), color: CATEGORY_COLORS.SAVINGS },
  ];

  const fixedExpenses = expenses.filter(e => e.isFixed);
  const varNeeds = expenses.filter(e => !e.isFixed && e.category === Category.NEEDS);
  const varWants = expenses.filter(e => !e.isFixed && e.category === Category.WANTS);
  const savings = expenses.filter(e => e.category === Category.SAVINGS);

  const sections = [
    { title: 'Gastos Fijos', data: fixedExpenses, color: '#64748b' },
    { title: 'Necesidades (Variables)', data: varNeeds, color: CATEGORY_COLORS.NEEDS },
    { title: 'Deseos (Variables)', data: varWants, color: CATEGORY_COLORS.WANTS },
    { title: 'Ahorro e Inversión', data: savings, color: CATEGORY_COLORS.SAVINGS },
  ];

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-20">
      <section className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {[
          { cat: Category.NEEDS, label: 'Necesidades', pct: '50%', color: CATEGORY_COLORS.NEEDS },
          { cat: Category.WANTS, label: 'Deseos', pct: '30%', color: CATEGORY_COLORS.WANTS },
          { cat: Category.SAVINGS, label: 'Ahorro', pct: '20%', color: CATEGORY_COLORS.SAVINGS },
        ].map((item) => {
          const spent = getSpentThisMonth(item.cat);
          const total = splits[item.cat];
          const remaining = total - spent;
          const isOver = remaining < 0;

          return (
            <div key={item.cat} className={`p-5 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
              <div className="flex justify-between items-center mb-4">
                <span className="text-[10px] font-black uppercase tracking-widest px-2 py-1 rounded-lg bg-slate-100 dark:bg-slate-800 text-slate-500">
                  {item.pct} {item.label}
                </span>
                <div className="w-2 h-2 rounded-full" style={{ backgroundColor: item.color }} />
              </div>
              <div className="space-y-1">
                <p className="text-[10px] font-bold text-slate-500 uppercase">Plantilla Mensual</p>
                <p className="text-xl font-black italic">{currencySymbol}{total.toLocaleString()}</p>
              </div>
              <div className="mt-4 pt-4 border-t border-dashed border-slate-200 dark:border-slate-800 flex justify-between items-end">
                <div>
                  <p className="text-[9px] font-bold text-slate-400 uppercase">Mes Queda</p>
                  <p className={`text-sm font-bold ${isOver ? 'text-rose-500' : 'text-emerald-500'}`}>
                    {currencySymbol}{remaining.toLocaleString()}
                  </p>
                </div>
                <div className="text-right">
                  <p className="text-[9px] font-bold text-slate-400 uppercase">Uso</p>
                  <p className="text-xs font-bold text-slate-600 dark:text-slate-300">
                    {total > 0 ? ((spent / total) * 100).toFixed(0) : 0}%
                  </p>
                </div>
              </div>
            </div>
          );
        })}
      </section>

      <div className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <h2 className="text-xl font-bold italic uppercase tracking-tight flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"/>
          Análisis Mensual (Proyectado)
        </h2>
        <div className="h-[300px] w-full mt-6">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} margin={{ top: 20, right: 30, left: 0, bottom: 0 }} barGap={8}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? "#1e293b" : "#f1f5f9"} />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: isDarkMode ? '#94a3b8' : '#64748b', fontSize: 12, fontWeight: 700 }} />
              <YAxis axisLine={false} tickLine={false} tick={{ fill: isDarkMode ? '#64748b' : '#94a3b8', fontSize: 10 }} />
              <Tooltip cursor={{ fill: isDarkMode ? '#1e293b' : '#f8fafc' }} contentStyle={{ borderRadius: '16px', border: 'none', backgroundColor: isDarkMode ? '#1e293b' : '#fff' }} />
              <Bar name="Presupuesto Mensual" dataKey="Presupuesto" fill={isDarkMode ? "#334155" : "#e2e8f0"} radius={[6, 6, 0, 0]} barSize={32} />
              <Bar name="Gastado Mes" dataKey="Gastado" radius={[6, 6, 0, 0]} barSize={32}>
                {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="space-y-4">
        <h2 className="text-xl font-bold italic uppercase tracking-tight px-2 flex items-center gap-2">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
          Historial por Categorías
        </h2>
        {sections.map(section => (
          <div key={section.title} className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
            <h3 className="text-sm font-black uppercase tracking-widest text-indigo-500 mb-4 flex items-center gap-2">
              <span className="w-1.5 h-1.5 rounded-full" style={{backgroundColor: section.color}}/>
              {section.title}
              <span className="ml-auto text-[10px] text-slate-400 bg-slate-100 dark:bg-slate-800 px-2 py-0.5 rounded-full">
                {section.data.length} registros
              </span>
            </h3>
            <div className="space-y-2">
              {section.data.length === 0 ? (
                <p className="text-xs text-slate-400 italic py-2">Sin registros en esta categoría.</p>
              ) : (
                section.data.slice().reverse().map(exp => (
                  <div key={exp.id} className={`flex items-center justify-between p-3 rounded-xl transition-all group ${isDarkMode ? 'hover:bg-slate-800' : 'hover:bg-slate-50'}`}>
                    <div className="flex items-center gap-3">
                      <div className="w-2 h-2 rounded-full shadow-sm" style={{ backgroundColor: CATEGORY_COLORS[exp.category] }} />
                      <div>
                        <div className="text-sm font-bold flex items-center gap-2 flex-wrap">
                          {exp.description}
                          {exp.isFixed && (
                            <div className="flex items-center gap-1">
                              <span className="text-[8px] bg-indigo-100 text-indigo-600 dark:bg-indigo-900/30 dark:text-indigo-400 px-1 rounded uppercase font-black">Fijo</span>
                              {exp.frequency && (
                                <span className="text-[8px] text-slate-400 font-bold uppercase italic">
                                  ({FREQUENCY_LABELS[exp.frequency]})
                                </span>
                              )}
                            </div>
                          )}
                        </div>
                        <p className="text-[10px] text-slate-500 font-bold uppercase">{new Date(exp.date).toLocaleDateString()} • {CATEGORY_LABELS[exp.category]}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="text-sm font-black">-${exp.amount.toLocaleString()}</span>
                      <button onClick={() => onDeleteExpense(exp.id)} className="p-2 opacity-0 group-hover:opacity-100 text-slate-300 hover:text-rose-500 transition-all">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                        </svg>
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default BudgetDetails;

import React from 'react';
import { UserProfile, Expense, Category, Frequency } from '../types';
import { CATEGORY_COLORS, CURRENCY_SYMBOLS, CATEGORY_LABELS } from '../constants';

interface FinancialSummaryProps {
  profile: UserProfile;
  expenses: Expense[];
  onClose: () => void;
  onGoToPlan: () => void;
  isDarkMode: boolean;
}

const FinancialSummary: React.FC<FinancialSummaryProps> = ({ profile, expenses, onClose, onGoToPlan, isDarkMode }) => {
  const currencySymbol = CURRENCY_SYMBOLS[profile.currency] || '$';

  const now = new Date();
  const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
  const startOfWeek = new Date(now);
  startOfWeek.setDate(now.getDate() - now.getDay());

  const monthExpenses = expenses.filter(e => new Date(e.date) >= startOfMonth);
  const weekExpenses = expenses.filter(e => new Date(e.date) >= startOfWeek);

  const totalMonth = monthExpenses.reduce((acc, curr) => acc + curr.amount, 0);
  const totalWeek = weekExpenses.reduce((acc, curr) => acc + curr.amount, 0);

  // Normalize income to monthly and weekly for comparison
  const getIncomeByPeriod = () => {
    let monthly = profile.income;
    if (profile.frequency === Frequency.WEEKLY) monthly = profile.income * 4;
    if (profile.frequency === Frequency.BIWEEKLY) monthly = profile.income * 2;
    return { monthly, weekly: monthly / 4 };
  };

  const income = getIncomeByPeriod();

  const getCatTotal = (exps: Expense[], cat: Category) => 
    exps.filter(e => e.category === cat).reduce((acc, curr) => acc + curr.amount, 0);

  return (
    <div className="fixed inset-0 z-50 flex items-end md:items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className={`w-full max-w-lg rounded-[2.5rem] p-8 shadow-2xl transition-colors overflow-y-auto max-h-[90vh] ${isDarkMode ? 'bg-slate-900 text-white' : 'bg-white text-slate-900'}`}>
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-black italic uppercase tracking-tighter">Resumen Financiero</h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="space-y-6">
          {/* Card: Monthly Performance */}
          <div className={`p-6 rounded-3xl border ${isDarkMode ? 'border-slate-800 bg-slate-800/50' : 'border-slate-100 bg-slate-50'}`}>
            <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Rendimiento Mensual</p>
            <div className="flex justify-between items-end">
              <div>
                <p className="text-3xl font-black">{currencySymbol}{totalMonth.toLocaleString()}</p>
                <p className="text-xs text-slate-500 font-bold uppercase">Gastado de {currencySymbol}{income.monthly.toLocaleString()}</p>
              </div>
              <div className={`text-xs font-black px-3 py-1 rounded-full ${totalMonth > income.monthly ? 'bg-rose-500/20 text-rose-500' : 'bg-emerald-500/20 text-emerald-500'}`}>
                {((totalMonth / income.monthly) * 100).toFixed(0)}%
              </div>
            </div>
            <div className="mt-4 h-2 w-full bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
              <div 
                className={`h-full transition-all duration-1000 ${totalMonth > income.monthly ? 'bg-rose-500' : 'bg-indigo-500'}`} 
                style={{ width: `${Math.min((totalMonth / income.monthly) * 100, 100)}%` }} 
              />
            </div>
          </div>

          {/* Card: Weekly Performance */}
          <div className={`p-6 rounded-3xl border ${isDarkMode ? 'border-slate-800 bg-slate-800/50' : 'border-slate-100 bg-slate-50'}`}>
            <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Rendimiento Semanal</p>
            <div className="flex justify-between items-end">
              <div>
                <p className="text-3xl font-black">{currencySymbol}{totalWeek.toLocaleString()}</p>
                <p className="text-xs text-slate-500 font-bold uppercase">Semana vs Presupuesto {currencySymbol}{income.weekly.toLocaleString()}</p>
              </div>
              <div className={`text-xs font-black px-3 py-1 rounded-full ${totalWeek > income.weekly ? 'bg-rose-500/20 text-rose-500' : 'bg-emerald-500/20 text-emerald-500'}`}>
                {((totalWeek / income.weekly) * 100).toFixed(0)}%
              </div>
            </div>
          </div>

          {/* Category Breakdown List */}
          <div className="space-y-3">
            <p className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-2">Desglose por Categoría (Mes)</p>
            {[Category.NEEDS, Category.WANTS, Category.SAVINGS].map(cat => (
              <div key={cat} className="flex items-center justify-between p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                <div className="flex items-center gap-3">
                  <div className="w-2 h-2 rounded-full" style={{ backgroundColor: CATEGORY_COLORS[cat] }} />
                  <span className="text-sm font-bold uppercase italic">{CATEGORY_LABELS[cat].split(' ')[0]}</span>
                </div>
                <span className="font-black">{currencySymbol}{getCatTotal(monthExpenses, cat).toLocaleString()}</span>
              </div>
            ))}
          </div>

          <button 
            onClick={onGoToPlan}
            className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl hover:bg-indigo-700 transition-all active:scale-95 mt-4"
          >
            Ver Detalles en Plan
          </button>
        </div>
      </div>
    </div>
  );
};

export default FinancialSummary;

import React, { useState, useEffect } from 'react';
import { UserProfile, Expense, Category, Frequency } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { CATEGORY_COLORS, CURRENCY_SYMBOLS, FREQUENCY_LABELS } from '../constants';
import FinancialSummary from './FinancialSummary';

interface DashboardProps {
  profile: UserProfile;
  expenses: Expense[];
  onAddExpense: (amount: number, category: Category, description: string, isFixed: boolean, frequency?: Frequency) => void;
  onNavigateToTab: (tab: 'budget') => void;
  isDarkMode: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ profile, expenses, onAddExpense, onNavigateToTab, isDarkMode }) => {
  const [selectedCat, setSelectedCat] = useState<Category>(Category.NEEDS);
  const [timeRemaining, setTimeRemaining] = useState<string>('');
  const [progressPercent, setProgressPercent] = useState(100);
  const [showSummary, setShowSummary] = useState(false);

  const getPeriodFilter = (dateStr: string, freq: Frequency) => {
    const d = new Date(dateStr);
    const now = new Date();

    if (freq === Frequency.MONTHLY) {
      return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    }

    const diffMs = now.getTime() - d.getTime();
    const diffDays = diffMs / (1000 * 60 * 60 * 24);

    if (freq === Frequency.WEEKLY) return diffDays <= 7;
    if (freq === Frequency.BIWEEKLY) return diffDays <= 14;
    return false;
  };

  const currentPeriodExpenses = expenses.filter(e => getPeriodFilter(e.date, profile.frequency));
  const totalPeriodExpenses = currentPeriodExpenses.reduce((acc, curr) => acc + curr.amount, 0);
  const balance = profile.income - totalPeriodExpenses;
  const currencySymbol = CURRENCY_SYMBOLS[profile.currency] || '$';

  const getPeriodDays = (freq: Frequency) => {
    if (freq === Frequency.WEEKLY) return 7;
    if (freq === Frequency.BIWEEKLY) return 14;
    return 30;
  };

  useEffect(() => {
    const updateCountdown = () => {
      if (!profile.lastLoginDate) return;

      const lastDate = new Date(profile.lastLoginDate);
      const today = new Date();
      const limitDays = getPeriodDays(profile.frequency);
      const limitMs = limitDays * 24 * 60 * 60 * 1000;

      const expiryTime = lastDate.getTime() + limitMs;
      const diffMs = expiryTime - today.getTime();

      if (diffMs <= 0) {
        setTimeRemaining('Ciclo Completado');
        setProgressPercent(0);
      } else {
        const days = Math.floor(diffMs / (1000 * 60 * 60 * 24));
        const hours = Math.floor((diffMs % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
        setTimeRemaining(`${days}d ${hours}h`);
        setProgressPercent((diffMs / limitMs) * 100);
      }
    };

    updateCountdown();
    const timer = setInterval(updateCountdown, 60000);
    return () => clearInterval(timer);
  }, [profile.lastLoginDate, profile.frequency]);

  const getCategoryTotal = (cat: Category) => 
    currentPeriodExpenses.filter(e => e.category === cat).reduce((acc, curr) => acc + curr.amount, 0);

  const chartData = [
    { name: 'Necesidades', value: getCategoryTotal(Category.NEEDS), color: CATEGORY_COLORS.NEEDS },
    { name: 'Deseos', value: getCategoryTotal(Category.WANTS), color: CATEGORY_COLORS.WANTS },
    { name: 'Ahorro', value: getCategoryTotal(Category.SAVINGS), color: CATEGORY_COLORS.SAVINGS },
  ].filter(d => d.value > 0);

  const periodLabel = profile.frequency === Frequency.WEEKLY ? 'Semanal' : profile.frequency === Frequency.BIWEEKLY ? 'Quincenal' : 'Mensual';

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className={`p-6 rounded-3xl border shadow-sm flex flex-col justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <div className="flex justify-between items-start">
            <span className="text-slate-500 text-sm font-medium uppercase tracking-wider">Balance {periodLabel}</span>
            <button 
              onClick={() => setShowSummary(true)}
              className="p-1 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg text-indigo-500"
              title="Resumen Detallado"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d="M2 11a1 1 0 011-1h2a1 1 0 011 1v5a1 1 0 01-1 1H3a1 1 0 01-1-1v-5zM8 7a1 1 0 011-1h2a1 1 0 011 1v9a1 1 0 01-1 1H9a1 1 0 01-1-1V7zM14 4a1 1 0 011-1h2a1 1 0 011 1v12a1 1 0 01-1 1h-2a1 1 0 01-1-1V4z" />
              </svg>
            </button>
          </div>
          <div className="flex items-end gap-2 mt-2">
            <span className="text-3xl font-bold">{currencySymbol}{balance.toLocaleString()}</span>
            <span className={`text-xs font-bold px-2 py-1 rounded-full ${balance >= 0 ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'}`}>
              {balance >= 0 ? 'Libre' : 'Excedido'}
            </span>
          </div>
        </div>

        <button 
          onClick={() => document.getElementById('quick-expense-form')?.scrollIntoView({ behavior: 'smooth' })}
          className={`relative p-6 rounded-3xl border shadow-sm flex flex-col justify-between transition-all group hover:scale-[1.02] text-left active:scale-95 overflow-hidden ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}
        >
          <div 
            className="absolute bottom-0 left-0 h-1 bg-orange-500/30 transition-all duration-1000"
            style={{ width: `${progressPercent}%` }}
          />
          <div className="flex justify-between items-start">
            <span className="text-slate-500 text-sm font-medium uppercase tracking-wider group-hover:text-indigo-500 transition-colors">Ciclo</span>
            <span className="text-[10px] font-black text-orange-500 uppercase">{timeRemaining}</span>
          </div>
          <div className="flex items-center gap-3 mt-2">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center transition-colors ${isDarkMode ? 'bg-orange-500/20 text-orange-400' : 'bg-orange-100 text-orange-500'} group-hover:bg-orange-500 group-hover:text-white`}>
              <span className="text-xl animate-pulse">🔥</span>
            </div>
            <div>
              <span className="text-2xl font-bold">{profile.streak} Racha</span>
              <p className="text-[10px] text-slate-400 font-bold uppercase">Meta: Ahorrar en cada ciclo</p>
            </div>
          </div>
        </button>

        <div className={`p-6 rounded-3xl border shadow-sm flex flex-col justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <span className="text-slate-500 text-sm font-medium uppercase tracking-wider">Gastos {periodLabel}</span>
          <span className="text-3xl font-bold text-rose-500 mt-2">{currencySymbol}{totalPeriodExpenses.toLocaleString()}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div id="quick-expense-form" className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <h3 className="text-lg font-bold mb-4 italic uppercase tracking-tight">Nuevo Movimiento</h3>
          <QuickExpenseForm onSubmit={onAddExpense} isDarkMode={isDarkMode} preSelectedCat={selectedCat} onCatChange={setSelectedCat} currencySymbol={currencySymbol} />
        </div>

        <div className={`p-6 rounded-3xl border shadow-sm transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <h3 className="text-lg font-bold mb-4 italic uppercase tracking-tight">Distribución Actual</h3>
          <div className="h-[200px] w-full">
            {chartData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={chartData}
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                    stroke="none"
                  >
                    {chartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', backgroundColor: isDarkMode ? '#1e293b' : '#ffffff', color: isDarkMode ? '#f1f5f9' : '#0f172a' }}
                    formatter={(value: number) => `${currencySymbol}${value.toLocaleString()}`}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full text-slate-500 text-sm italic font-medium">
                Sin movimientos en este {periodLabel.toLowerCase()}
              </div>
            )}
          </div>
          <div className="mt-4 flex justify-around text-[10px] font-bold uppercase tracking-widest text-slate-500">
            <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full" style={{backgroundColor: CATEGORY_COLORS.NEEDS}}/> Necesidades</div>
            <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full" style={{backgroundColor: CATEGORY_COLORS.WANTS}}/> Deseos</div>
            <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full" style={{backgroundColor: CATEGORY_COLORS.SAVINGS}}/> Ahorro</div>
          </div>
        </div>
      </div>

      {showSummary && (
        <FinancialSummary 
          profile={profile} 
          expenses={expenses} 
          onClose={() => setShowSummary(false)} 
          onGoToPlan={() => {
            setShowSummary(false);
            onNavigateToTab('budget');
          }}
          isDarkMode={isDarkMode}
        />
      )}
    </div>
  );
};

const QuickExpenseForm: React.FC<{ 
  onSubmit: (a: number, c: Category, d: string, f: boolean, freq?: Frequency) => void, 
  isDarkMode: boolean, 
  preSelectedCat: Category,
  onCatChange: (c: Category) => void,
  currencySymbol: string
}> = ({ onSubmit, isDarkMode, preSelectedCat, onCatChange, currencySymbol }) => {
  const [amount, setAmount] = React.useState('');
  const [desc, setDesc] = React.useState('');
  const [isFixed, setIsFixed] = React.useState(false);
  const [frequency, setFrequency] = React.useState<Frequency>(Frequency.MONTHLY);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !desc) return;
    onSubmit(parseFloat(amount), preSelectedCat, desc, isFixed, isFixed ? frequency : undefined);
    setAmount('');
    setDesc('');
    setIsFixed(false);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="grid grid-cols-2 gap-4">
        <div className="relative">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 font-bold">{currencySymbol}</span>
          <input 
            type="number" 
            placeholder="Monto" 
            required
            value={amount} 
            onChange={e => setAmount(e.target.value)}
            className={`w-full border-none rounded-xl p-3 pl-8 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors ${isDarkMode ? 'bg-slate-800 text-white placeholder-slate-500' : 'bg-slate-50 placeholder-slate-400'}`}
          />
        </div>
        <select 
          value={preSelectedCat} 
          onChange={e => onCatChange(e.target.value as Category)}
          className={`border-none rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors ${isDarkMode ? 'bg-slate-800 text-white' : 'bg-slate-50'}`}
        >
          <option value={Category.NEEDS}>Necesidad</option>
          <option value={Category.WANTS}>Deseo</option>
          <option value={Category.SAVINGS}>Ahorro</option>
        </select>
      </div>
      <input 
        type="text" 
        placeholder="Descripción (ej. Netflix, Renta...)" 
        required
        value={desc} 
        onChange={e => setDesc(e.target.value)}
        className={`w-full border-none rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none transition-colors ${isDarkMode ? 'bg-slate-800 text-white placeholder-slate-500' : 'bg-slate-50 placeholder-slate-400'}`}
      />

      <div className="flex flex-col gap-3 px-2">
        <div className="flex items-center gap-2">
          <input 
            type="checkbox" 
            id="isFixed" 
            checked={isFixed}
            onChange={e => setIsFixed(e.target.checked)}
            className="w-4 h-4 text-indigo-600 rounded focus:ring-indigo-500"
          />
          <label htmlFor="isFixed" className="text-xs font-bold uppercase text-slate-500 tracking-tight cursor-pointer">
            ¿Es un {preSelectedCat === Category.WANTS ? 'deseo' : 'gasto'} fijo?
          </label>
        </div>

        {isFixed && (
          <div className="animate-in slide-in-from-left-2 duration-300">
             <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">Frecuencia del Gasto Fijo</label>
             <div className="grid grid-cols-3 gap-2">
                {Object.entries(FREQUENCY_LABELS).map(([key, label]) => (
                  <button
                    key={key}
                    type="button"
                    onClick={() => setFrequency(key as Frequency)}
                    className={`py-2 text-[10px] font-black uppercase tracking-tighter rounded-lg border transition-all ${
                      frequency === key
                        ? 'bg-indigo-600 text-white border-indigo-600 shadow-md'
                        : isDarkMode ? 'bg-slate-800 text-slate-400 border-slate-700' : 'bg-white text-slate-600 border-slate-200'
                    }`}
                  >
                    {label}
                  </button>
                ))}
             </div>
          </div>
        )}
      </div>

      <button type="submit" className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg active:scale-95">
        Guardar Transacción
      </button>
    </form>
  );
};

export default Dashboard;

import React, { useEffect, useState, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { getFinancialAdvice } from '../services/geminiService';
import { UserProfile, Expense, SavingsGoal } from '../types';
import { CURRENCY_SYMBOLS } from '../constants';

interface AIChatProps {
  profile: UserProfile;
  expenses: Expense[];
  goals: SavingsGoal[];
  onUpdateGoals: (goals: SavingsGoal[]) => void;
  isDarkMode: boolean;
}

interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

const AIChat: React.FC<AIChatProps> = ({ profile, expenses, goals, onUpdateGoals, isDarkMode }) => {
  const [tips, setTips] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [userInput, setUserInput] = useState('');
  const [isChatting, setIsChatting] = useState(false);
  const [newGoalName, setNewGoalName] = useState('');
  const [newGoalTarget, setNewGoalTarget] = useState('');
  const [isAddingGoal, setIsAddingGoal] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const currencySymbol = CURRENCY_SYMBOLS[profile.currency] || '$';

  useEffect(() => {
    const fetchTips = async () => {
      setLoading(true);
      const advice = await getFinancialAdvice(profile, expenses, goals);
      setTips(advice);
      setLoading(false);
    };
    fetchTips();
  }, [profile, expenses, goals]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chatMessages]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userInput.trim() || isChatting) return;

    const userText = userInput;
    setUserInput('');
    setChatMessages(prev => [...prev, { role: 'user', text: userText }]);
    setIsChatting(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const context = `Usuario: ${profile.username}. Ingreso: ${profile.income} ${profile.currency}. Gastos: ${JSON.stringify(expenses.slice(-10))}. Metas: ${JSON.stringify(goals)}.`;

      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: `Eres Zcorpion, un asistente financiero experto. Responde preguntas cortas y directas basadas en el contexto del usuario: ${context}. Sé motivador y realista.`
        }
      });

      const response = await chat.sendMessage({ message: userText });
      const botText = response.text || "Lo siento, tuve un problema analizando eso.";
      setChatMessages(prev => [...prev, { role: 'model', text: botText }]);
    } catch (err) {
      console.error(err);
      setChatMessages(prev => [...prev, { role: 'model', text: "Ocurrió un error con la conexión a la IA." }]);
    } finally {
      setIsChatting(false);
    }
  };

  const handleAddGoal = (e: React.FormEvent) => {
    e.preventDefault();
    const target = parseFloat(newGoalTarget);
    if (!newGoalName || isNaN(target) || target <= 0) return;

    const newGoal: SavingsGoal = {
      id: Math.random().toString(36).substr(2, 9),
      name: newGoalName,
      targetAmount: target,
      currentAmount: 0
    };
    onUpdateGoals([...goals, newGoal]);
    setNewGoalName('');
    setNewGoalTarget('');
    setIsAddingGoal(false);
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      <section className={`p-6 rounded-[2rem] border shadow-lg overflow-hidden flex flex-col h-[500px] transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <div className="flex items-center gap-3 mb-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold">ZC</div>
          <div>
            <h2 className="font-black italic uppercase text-lg leading-tight tracking-tight">Chat con Zcorpion</h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Consejos en tiempo real</p>
          </div>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto space-y-4 mb-4 pr-2 custom-scrollbar">
          {chatMessages.length === 0 && (
            <div className="text-center py-10">
              <p className="text-slate-400 text-sm italic">"¿Cómo puedo ahorrar más este mes?"<br/>"¿Es buen momento para comprar un auto?"</p>
            </div>
          )}
          {chatMessages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : (isDarkMode ? 'bg-slate-800 text-slate-200' : 'bg-slate-100 text-slate-800') + ' rounded-tl-none'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isChatting && (
            <div className="flex justify-start">
              <div className="bg-slate-100 dark:bg-slate-800 p-3 rounded-2xl rounded-tl-none animate-pulse text-xs font-bold text-slate-500 uppercase">
                Zcorpion pensando...
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleSendMessage} className="relative">
          <input 
            type="text"
            value={userInput}
            onChange={e => setUserInput(e.target.value)}
            placeholder="Pregúntale algo a Zcorpion..."
            className={`w-full p-4 pr-12 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all ${isDarkMode ? 'bg-slate-800 text-white' : 'bg-slate-50 text-slate-900'}`}
          />
          <button type="submit" disabled={isChatting} className="absolute right-3 top-1/2 -translate-y-1/2 text-indigo-500 hover:scale-110 transition-transform disabled:opacity-50">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor">
              <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
            </svg>
          </button>
        </form>
      </section>

      {/* Goal Management Section - RESTORED TO PREVIOUS DESIGN */}
      <section className={`p-6 rounded-[2rem] border shadow-lg transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-black italic uppercase flex items-center gap-2">
            <span className="text-xl">🎯</span> Metas de Ahorro
          </h3>
          <button 
            onClick={() => setIsAddingGoal(!isAddingGoal)}
            className="w-8 h-8 bg-indigo-600 text-white rounded-xl flex items-center justify-center shadow-lg hover:scale-110 transition-transform"
          >
            {isAddingGoal ? '×' : '+'}
          </button>
        </div>

        {isAddingGoal && (
          <form onSubmit={handleAddGoal} className="mb-6 space-y-3 p-4 rounded-2xl bg-indigo-50 dark:bg-slate-800 animate-in slide-in-from-top-4">
            <input 
              type="text" 
              placeholder="¿Qué quieres lograr?" 
              value={newGoalName}
              onChange={e => setNewGoalName(e.target.value)}
              className={`w-full p-3 rounded-xl border-none outline-none text-sm ${isDarkMode ? 'bg-slate-700' : 'bg-white'}`}
            />
            <div className="relative">
              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs">{currencySymbol}</span>
              <input 
                type="number" 
                placeholder="Monto objetivo" 
                value={newGoalTarget}
                onChange={e => setNewGoalTarget(e.target.value)}
                className={`w-full p-3 pl-7 rounded-xl border-none outline-none text-sm ${isDarkMode ? 'bg-slate-700' : 'bg-white'}`}
              />
            </div>
            <button type="submit" className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold text-xs uppercase tracking-widest shadow-lg">
              Confirmar Meta
            </button>
          </form>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {goals.length === 0 && !isAddingGoal && (
            <p className="text-xs text-slate-500 italic text-center col-span-2 py-4">Define tu próxima meta y deja que Zcorpion te ayude a llegar.</p>
          )}
          {goals.map(goal => {
            const progress = Math.min((goal.currentAmount / goal.targetAmount) * 100, 100);
            return (
              <div key={goal.id} className={`p-5 rounded-3xl border ${isDarkMode ? 'border-slate-800 bg-slate-800/30' : 'border-slate-100 bg-slate-50'} flex flex-col justify-between`}>
                <div className="flex justify-between items-start mb-4">
                  <div>
                    <p className="text-sm font-black uppercase italic tracking-tight">{goal.name}</p>
                    <p className="text-[10px] text-slate-500 font-bold uppercase">{currencySymbol}{goal.currentAmount.toLocaleString()} / {currencySymbol}{goal.targetAmount.toLocaleString()}</p>
                  </div>
                  <span className="text-[10px] font-black text-indigo-500 bg-indigo-500/10 px-2 py-1 rounded-lg">{progress.toFixed(0)}%</span>
                </div>
                <div className="h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-indigo-500 transition-all duration-1000" 
                    style={{ width: `${progress}%` }} 
                  />
                </div>
              </div>
            );
          })}
        </div>
      </section>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {loading ? Array(3).fill(0).map((_, i) => <div key={i} className="h-40 animate-pulse rounded-3xl bg-slate-200 dark:bg-slate-800" />) : (
          tips.map((tip, idx) => (
            <div key={idx} className={`p-5 rounded-3xl border shadow-sm ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
              <h4 className="font-bold text-sm mb-1 uppercase text-indigo-500">{tip.title}</h4>
              <p className="text-xs text-slate-500 leading-relaxed">{tip.content}</p>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

