  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    return localStorage.getItem('finanza_dark_mode') === 'true';
  });

  const getPeriodDays = (freq: Frequency) => {
    if (freq === Frequency.WEEKLY) return 7;
    if (freq === Frequency.BIWEEKLY) return 14;
    return 30;
  };

  // Logic to handle cycle reset and streak failure
  useEffect(() => {
    const savedProfile = localStorage.getItem('finanza_profile');
    const savedExpenses = localStorage.getItem('finanza_expenses');
    const savedGoals = localStorage.getItem('finanza_goals');

    let currentProfile: UserProfile | null = savedProfile ? JSON.parse(savedProfile) : null;
    const currentExpenses: Expense[] = savedExpenses ? JSON.parse(savedExpenses) : [];

    if (currentProfile && currentProfile.lastLoginDate) {
      const lastCycleStart = new Date(currentProfile.lastLoginDate);
      const today = new Date();
      const diffMs = today.getTime() - lastCycleStart.getTime();
      const diffDays = diffMs / (1000 * 3600 * 24);
      const limit = getPeriodDays(currentProfile.frequency);

      // If the cycle time has exceeded the limit (timer reached zero)
      if (diffDays >= limit) {
        // Check if any activity happened in the cycle that just ended
        const expensesInLastCycle = currentExpenses.filter(e => {
          const expenseDate = new Date(e.date);
          return expenseDate >= lastCycleStart && expenseDate < today;
        });

        // If no activity, reset streak to zero
        if (expensesInLastCycle.length === 0) {
          currentProfile.streak = 0;
        }

        // Reset cycle start to today
        currentProfile.lastLoginDate = new Date().toISOString();
        setProfile(currentProfile);
      } else {
        setProfile(currentProfile);
      }
    }

    if (savedExpenses) setExpenses(currentExpenses);
    if (savedGoals) setGoals(JSON.parse(savedGoals));
  }, []);

  useEffect(() => {
    if (profile) localStorage.setItem('finanza_profile', JSON.stringify(profile));
