import React, { useEffect, useState, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { getFinancialAdvice } from '../services/geminiService';
import { UserProfile, Expense, SavingsGoal } from '../types';
import { CURRENCY_SYMBOLS } from '../constants';

interface AIChatProps {
  profile: UserProfile;
  expenses: Expense[];
  goals: SavingsGoal[];
  onUpdateGoals: (goals: SavingsGoal[]) => void;
  isDarkMode: boolean;
}

interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

const AIChat: React.FC<AIChatProps> = ({ profile, expenses, goals, onUpdateGoals, isDarkMode }) => {
  const [tips, setTips] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [userInput, setUserInput] = useState('');
  const [isChatting, setIsChatting] = useState(false);
  const [newGoalName, setNewGoalName] = useState('');
  const [newGoalTarget, setNewGoalTarget] = useState('');
  const [isAddingGoal, setIsAddingGoal] = useState(false);
  const [contributingTo, setContributingTo] = useState<string | null>(null);
  const [contributionAmount, setContributionAmount] = useState('');

  const scrollRef = useRef<HTMLDivElement>(null);
  const currencySymbol = CURRENCY_SYMBOLS[profile.currency] || '$';

  useEffect(() => {
    const fetchTips = async () => {
      setLoading(true);
      const advice = await getFinancialAdvice(profile, expenses, goals);
      setTips(advice);
      setLoading(false);
    };
    fetchTips();
  }, [profile, expenses, goals]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chatMessages]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userInput.trim() || isChatting) return;

    const userText = userInput;
    setUserInput('');
    setChatMessages(prev => [...prev, { role: 'user', text: userText }]);
    setIsChatting(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const context = `Usuario: ${profile.username}. Ingreso: ${profile.income} ${profile.currency}. Gastos: ${JSON.stringify(expenses.slice(-10))}. Metas: ${JSON.stringify(goals)}.`;

      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: `Eres Zcorpion, un asistente financiero experto. Responde preguntas cortas y directas basadas en el contexto del usuario: ${context}. Sé motivador y realista.`
        }
      });

      const response = await chat.sendMessage({ message: userText });
      const botText = response.text || "Lo siento, tuve un problema analizando eso.";
      setChatMessages(prev => [...prev, { role: 'model', text: botText }]);
    } catch (err) {
      console.error(err);
      setChatMessages(prev => [...prev, { role: 'model', text: "Ocurrió un error con la conexión a la IA." }]);
    } finally {
      setIsChatting(false);
    }
  };

  const handleAddGoal = (e: React.FormEvent) => {
    e.preventDefault();
    const target = parseFloat(newGoalTarget);
    if (!newGoalName || isNaN(target) || target <= 0) return;

    const newGoal: SavingsGoal = {
      id: Math.random().toString(36).substr(2, 9),
      name: newGoalName,
      targetAmount: target,
      currentAmount: 0
    };
    onUpdateGoals([...goals, newGoal]);
    setNewGoalName('');
    setNewGoalTarget('');
    setIsAddingGoal(false);
  };

  const handleContribute = (goalId: string) => {
    const amount = parseFloat(contributionAmount);
    if (isNaN(amount) || amount <= 0) return;

    const updatedGoals = goals.map(g => {
      if (g.id === goalId) {
        return { ...g, currentAmount: g.currentAmount + amount };
      }
      return g;
    });

    onUpdateGoals(updatedGoals);
    setContributionAmount('');
    setContributingTo(null);
  };

  const handleDeleteGoal = (goalId: string) => {
    if (window.confirm('¿Estás seguro de que quieres eliminar esta meta de ahorro?')) {
      onUpdateGoals(goals.filter(g => g.id !== goalId));
    }
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      <section className={`p-6 rounded-[2rem] border shadow-lg overflow-hidden flex flex-col h-[500px] transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <div className="flex items-center gap-3 mb-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold">ZC</div>
          <div>
            <h2 className="font-black italic uppercase text-lg leading-tight tracking-tight">Chat con Zcorpion</h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Consejos en tiempo real</p>
          </div>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto space-y-4 mb-4 pr-2 custom-scrollbar">
          {chatMessages.length === 0 && (
            <div className="text-center py-10">
              <p className="text-slate-400 text-sm italic">"¿Cómo puedo ahorrar más este mes?"<br/>"¿Es buen momento para comprar un auto?"</p>
            </div>
          )}
          {chatMessages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : (isDarkMode ? 'bg-slate-800 text-slate-200' : 'bg-slate-100 text-slate-800') + ' rounded-tl-none'
              }`}>
                {msg.text}
              </div>
            </div>
          ))}
          {isChatting && (
            <div className="flex justify-start">
              <div className="bg-slate-100 dark:bg-slate-800 p-3 rounded-2xl rounded-tl-none animate-pulse text-xs font-bold text-slate-500 uppercase">
                Zcorpion pensando...
              </div>
            </div>
          )}
        </div>

        <form onSubmit={handleSendMessage} className="relative">
          <input 
            type="text"
            value={userInput}
            onChange={e => setUserInput(e.target.value)}
            placeholder="Pregúntale algo a Zcorpion..."
            className={`w-full p-4 pr-12 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all ${isDarkMode ? 'bg-slate-800 text-white' : 'bg-slate-50 text-slate-900'}`}
          />
          <button type="submit" disabled={isChatting} className="absolute right-3 top-1/2 -translate-y-1/2 text-indigo-500 hover:scale-110 transition-transform disabled:opacity-50">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor">
              <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
            </svg>
          </button>
        </form>
      </section>

      {/* Goal Management Section - Updated with Delete option */}
      <section className={`p-6 rounded-[2rem] border shadow-lg transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-black italic uppercase flex items-center gap-2">
            <span className="text-xl">🎯</span> Metas de Ahorro
          </h3>
          <button 
            onClick={() => setIsAddingGoal(!isAddingGoal)}
            className="w-8 h-8 bg-indigo-600 text-white rounded-xl flex items-center justify-center shadow-lg hover:scale-110 transition-transform"
          >
            {isAddingGoal ? '×' : '+'}
          </button>
        </div>

        {isAddingGoal && (
          <form onSubmit={handleAddGoal} className="mb-6 space-y-3 p-4 rounded-2xl bg-indigo-50 dark:bg-slate-800 animate-in slide-in-from-top-4">
            <input 
              type="text" 
              placeholder="¿Qué quieres lograr?" 
              value={newGoalName}
              onChange={e => setNewGoalName(e.target.value)}
              className={`w-full p-3 rounded-xl border-none outline-none text-sm ${isDarkMode ? 'bg-slate-700' : 'bg-white'}`}
            />
            <div className="relative">
              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs">{currencySymbol}</span>
              <input 
                type="number" 
                placeholder="Monto objetivo" 
                value={newGoalTarget}
                onChange={e => setNewGoalTarget(e.target.value)}
                className={`w-full p-3 pl-7 rounded-xl border-none outline-none text-sm ${isDarkMode ? 'bg-slate-700' : 'bg-white'}`}
              />
            </div>
            <button type="submit" className="w-full bg-indigo-600 text-white py-3 rounded-xl font-bold text-xs uppercase tracking-widest shadow-lg">
              Confirmar Meta
            </button>
          </form>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {goals.length === 0 && !isAddingGoal && (
            <p className="text-xs text-slate-500 italic text-center col-span-2 py-4">Define tu próxima meta y deja que Zcorpion te ayude a llegar.</p>
          )}
          {goals.map(goal => {
            const progress = Math.min((goal.currentAmount / goal.targetAmount) * 100, 100);
            const isContributing = contributingTo === goal.id;

            return (
              <div key={goal.id} className={`p-5 rounded-3xl border transition-all ${isDarkMode ? 'border-slate-800 bg-slate-800/30' : 'border-slate-100 bg-slate-50'} flex flex-col justify-between hover:shadow-md relative group`}>
                <div className="flex justify-between items-start mb-2">
                  <div>
                    <p className="text-sm font-black uppercase italic tracking-tight">{goal.name}</p>
                    <p className="text-[10px] text-slate-500 font-bold uppercase">{currencySymbol}{goal.currentAmount.toLocaleString()} / {currencySymbol}{goal.targetAmount.toLocaleString()}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-[10px] font-black text-indigo-500 bg-indigo-500/10 px-2 py-1 rounded-lg">{progress.toFixed(0)}%</span>

                    <button 
                      onClick={() => setContributingTo(isContributing ? null : goal.id)}
                      title="Sumar fondos"
                      className={`p-1.5 rounded-lg transition-colors ${isContributing ? 'bg-indigo-600 text-white' : 'bg-slate-200 dark:bg-slate-700 text-slate-500 dark:text-slate-400 hover:bg-indigo-500 hover:text-white'}`}
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9 9V5a1 1 0 112 0v4h4a1 1 0 110 2h-4v4a1 1 0 11-2 0v-4H5a1 1 0 110-2h4z" clipRule="evenodd" />
                      </svg>
                    </button>

                    <button 
                      onClick={() => handleDeleteGoal(goal.id)}
                      title="Eliminar meta"
                      className="p-1.5 rounded-lg bg-rose-500/10 text-rose-500 hover:bg-rose-500 hover:text-white transition-all opacity-0 group-hover:opacity-100"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                      </svg>
                    </button>
                  </div>
                </div>

                {isContributing && (
                  <div className="mt-2 mb-4 flex gap-2 animate-in slide-in-from-top-2 duration-200">
                    <div className="relative flex-1">
                      <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[10px] text-slate-400 font-bold">{currencySymbol}</span>
                      <input 
                        type="number"
                        placeholder="Monto"
                        autoFocus
                        value={contributionAmount}
                        onChange={(e) => setContributionAmount(e.target.value)}
                        className={`w-full p-2 pl-5 rounded-xl border-none outline-none text-xs font-bold ${isDarkMode ? 'bg-slate-700' : 'bg-white'}`}
                      />
                    </div>
                    <button 
                      onClick={() => handleContribute(goal.id)}
                      className="bg-indigo-600 text-white px-3 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-sm active:scale-95"
                    >
                      Sumar
                    </button>
                  </div>
                )}

                <div className="h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden mt-2">
                  <div 
                    className="h-full bg-indigo-500 transition-all duration-1000" 
                    style={{ width: `${progress}%` }} 
                  />
                </div>
              </div>
            );
          })}
        </div>
      </section>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {loading ? Array(3).fill(0).map((_, i) => <div key={i} className="h-40 animate-pulse rounded-3xl bg-slate-200 dark:bg-slate-800" />) : (
          tips.map((tip, idx) => (
            <div key={idx} className={`p-5 rounded-3xl border shadow-sm ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
              <h4 className="font-bold text-sm mb-1 uppercase text-indigo-500">{tip.title}</h4>
              <p className="text-xs text-slate-500 leading-relaxed">{tip.content}</p>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default AIChat;

export enum Category {
  NEEDS = 'NEEDS',
  WANTS = 'WANTS',
  SAVINGS = 'SAVINGS'
}

export enum Frequency {
  MONTHLY = 'MONTHLY',
  BIWEEKLY = 'BIWEEKLY',
  WEEKLY = 'WEEKLY'
}

export interface ReminderConfig {
  enabled: boolean;
  time: string; // HH:mm
  frequency: 'DAILY' | 'WEEKLY';
  customMessage?: string;
}

export interface Expense {
  id: string;
  amount: number;
  category: Category;
  description: string;
  date: string;
  isFixed?: boolean;
  frequency?: Frequency;
}

export interface UserProfile {
  username: string;
  income: number;
  frequency: Frequency;
  currency: string;
  streak: number;
  lastLoginDate: string;
  lastStreakDate?: string; // Nueva propiedad para racha diaria
  reminders?: ReminderConfig;
}

export interface BudgetSplit {
  needs: number;
  wants: number;
  savings: number;
}

export interface SavingsGoal {
  id: string;
  name: string;
  targetAmount: number;
  currentAmount: number;
}

import React, { useState, useEffect } from 'react';
import { UserProfile, Expense, Frequency, Category, SavingsGoal } from './types';
import Onboarding from './components/Onboarding';
import Dashboard from './components/Dashboard';
import BudgetDetails from './components/BudgetDetails';
import AIChat from './components/AIChat';
import Academy from './components/Academy';
import Settings from './components/Settings';
import Tutorial from './components/Tutorial';
import { FREQUENCY_LABELS, CURRENCY_SYMBOLS } from './constants';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [goals, setGoals] = useState<SavingsGoal[]>([]);
  const [showTutorial, setShowTutorial] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'budget' | 'chat' | 'academy' | 'settings'>('dashboard');
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    return localStorage.getItem('finanza_dark_mode') === 'true';
  });

  useEffect(() => {
    const savedProfile = localStorage.getItem('finanza_profile');
    const savedExpenses = localStorage.getItem('finanza_expenses');
    const savedGoals = localStorage.getItem('finanza_goals');
    const hasSeenTutorial = localStorage.getItem('finanza_tutorial_seen');

    let currentProfile: UserProfile | null = savedProfile ? JSON.parse(savedProfile) : null;
    const currentExpenses: Expense[] = savedExpenses ? JSON.parse(savedExpenses) : [];

    if (currentProfile) {
      if (!hasSeenTutorial) setShowTutorial(true);

      // Lógica de Racha Diaria al Cargar
      const today = new Date();
      today.setHours(0, 0, 0, 0);

      if (currentProfile.lastStreakDate) {
        const lastStreak = new Date(currentProfile.lastStreakDate);
        lastStreak.setHours(0, 0, 0, 0);

        const diffTime = today.getTime() - lastStreak.getTime();
        const diffDays = Math.floor(diffTime / (1000 * 3600 * 24));

        // Si ha pasado más de 1 día sin registrar nada, la racha se rompe
        if (diffDays > 1) {
          currentProfile.streak = 0;
        }
      } else if (currentProfile.streak > 0) {
        // Fallback para perfiles antiguos
        currentProfile.streak = 0;
      }

      currentProfile.lastLoginDate = new Date().toISOString();
      setProfile(currentProfile);
    }

    if (savedExpenses) setExpenses(currentExpenses);
    if (savedGoals) setGoals(JSON.parse(savedGoals));
  }, []);

  useEffect(() => {
    if (profile) localStorage.setItem('finanza_profile', JSON.stringify(profile));
    if (expenses.length >= 0) localStorage.setItem('finanza_expenses', JSON.stringify(expenses));
    if (goals.length >= 0) localStorage.setItem('finanza_goals', JSON.stringify(goals));
    localStorage.setItem('finanza_dark_mode', isDarkMode.toString());
  }, [profile, expenses, goals, isDarkMode]);

  const handleOnboardingComplete = (username: string, income: number, frequency: Frequency, currency: string) => {
    const newProfile: UserProfile = {
      username,
      income,
      frequency,
      currency,
      streak: 0,
      lastLoginDate: new Date().toISOString(),
      lastStreakDate: undefined,
      reminders: {
        enabled: false,
        time: '20:00',
        frequency: 'DAILY',
        customMessage: '¡Es hora de registrar tus movimientos! No olvides tus gastos fijos 🦂'
      }
    };
    setProfile(newProfile);
    setShowTutorial(true);
  };

  const completeTutorial = () => {
    setShowTutorial(false);
    localStorage.setItem('finanza_tutorial_seen', 'true');
  };

  const addExpense = (amount: number, category: Category, description: string, isFixed: boolean, frequency?: Frequency) => {
    if (!profile) return;

    const newExpense: Expense = {
      id: Math.random().toString(36).substr(2, 9),
      amount,
      category,
      description,
      isFixed,
      frequency: isFixed ? (frequency || profile.frequency) : undefined,
      date: new Date().toISOString()
    };

    setExpenses([...expenses, newExpense]);

    // Lógica de Racha Diaria al Agregar Gasto
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    let newStreak = profile.streak;
    let newLastStreakDate = profile.lastStreakDate;

    if (!profile.lastStreakDate) {
      newStreak = 1;
      newLastStreakDate = today.toISOString();
    } else {
      const lastStreak = new Date(profile.lastStreakDate);
      lastStreak.setHours(0, 0, 0, 0);

      const diffTime = today.getTime() - lastStreak.getTime();
      const diffDays = Math.floor(diffTime / (1000 * 3600 * 24));

      if (diffDays === 1) {
        newStreak += 1;
        newLastStreakDate = today.toISOString();
      } else if (diffDays > 1) {
        newStreak = 1;
        newLastStreakDate = today.toISOString();
      }
      // Si diffDays === 0, ya registró hoy, no cambia racha
    }

    setProfile({ ...profile, streak: newStreak, lastStreakDate: newLastStreakDate });
  };

  const deleteExpense = (id: string) => setExpenses(expenses.filter(e => e.id !== id));
  const updateGoals = (newGoals: SavingsGoal[]) => setGoals(newGoals);
  const handleUpdateProfile = (updates: Partial<UserProfile>) => { if (profile) setProfile({ ...profile, ...updates }); };

  const logout = () => {
    localStorage.clear();
    setProfile(null); setExpenses([]); setGoals([]); setActiveTab('dashboard');
  };

  if (!profile) return <Onboarding onComplete={handleOnboardingComplete} />;

  const currencySymbol = CURRENCY_SYMBOLS[profile.currency] || '$';
  const periodLabel = profile.frequency === Frequency.WEEKLY ? 'Semanal' : profile.frequency === Frequency.BIWEEKLY ? 'Quincenal' : 'Mensual';

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-300 ${isDarkMode ? 'dark bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      {showTutorial && <Tutorial onComplete={completeTutorial} isDarkMode={isDarkMode} />}

      <header className={`border-b sticky top-0 z-30 px-6 py-4 flex items-center justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800 shadow-xl' : 'bg-white border-slate-100 shadow-sm'}`}>
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-xs">ZC</div>
          <h1 className="text-xl font-black tracking-tight italic uppercase">ZCORPION</h1>
        </div>
        <button onClick={() => setActiveTab('settings')} className={`p-2 rounded-xl border-2 transition-all ${isDarkMode ? 'bg-slate-800 border-indigo-900' : 'bg-slate-50 border-indigo-50'} ${activeTab === 'settings' ? 'ring-2 ring-indigo-500 scale-110' : ''}`}>
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-indigo-500" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M11.49 3.17c-.38-1.56-2.6-1.56-2.98 0a1.532 1.532 0 01-2.286.948c-1.372-.836-2.942.734-2.106 2.106.54.886.061 2.042-.947 2.287-1.561.379-1.561 2.6 0 2.978a1.532 1.532 0 01.947 2.287c-.836 1.372.734 2.942 2.106 2.106a1.532 1.532 0 012.287.947c.379 1.561 2.6 1.561 2.978 0a1.533 1.533 0 012.287-.947c1.372.836 2.942-.734 2.106-2.106a1.533 1.533 0 01.947-2.287c1.561-.379 1.561-2.6 0-2.978a1.532 1.532 0 01-.947-2.287c.836-1.372-.734-2.942-2.106-2.106a1.532 1.532 0 01-2.287-.947zM10 13a3 3 0 100-6 3 3 0 000 6z" clipRule="evenodd" />
          </svg>
        </button>
      </header>

      <main className="flex-1 max-w-5xl w-full mx-auto p-4 md:p-6 mb-24">
        {activeTab !== 'settings' && (
          <div className="mb-8 animate-in fade-in slide-in-from-left-4 duration-500">
            <h2 className="text-3xl font-black italic leading-tight">Hola, {profile.username} 👋</h2>
            <div className="flex items-center gap-2 mt-1">
              <span className="text-[10px] font-black uppercase tracking-widest text-indigo-500">
                Ingreso {periodLabel}: {currencySymbol}{profile.income.toLocaleString()}
              </span>
              <span className="w-1 h-1 rounded-full bg-slate-300"/>
              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{FREQUENCY_LABELS[profile.frequency]}</span>
            </div>
          </div>
        )}

        {activeTab === 'dashboard' && <Dashboard profile={profile} expenses={expenses} onAddExpense={addExpense} onNavigateToTab={(tab) => setActiveTab(tab)} isDarkMode={isDarkMode} />}
        {activeTab === 'budget' && <BudgetDetails profile={profile} expenses={expenses} onDeleteExpense={deleteExpense} isDarkMode={isDarkMode} />}
        {activeTab === 'chat' && <AIChat profile={profile} expenses={expenses} goals={goals} onUpdateGoals={updateGoals} isDarkMode={isDarkMode} />}
        {activeTab === 'academy' && <Academy isDarkMode={isDarkMode} />}
        {activeTab === 'settings' && <Settings isDarkMode={isDarkMode} toggleDarkMode={() => setIsDarkMode(!isDarkMode)} onLogout={logout} profile={profile} onUpdateProfile={handleUpdateProfile} />}
      </main>

      <nav className={`fixed bottom-0 left-0 right-0 border-t p-2 md:p-4 z-40 transition-colors backdrop-blur-md ${isDarkMode ? 'bg-slate-900/80 border-slate-800' : 'bg-white/80 border-slate-100'}`}>
        <div className="max-w-xl mx-auto flex justify-around">
          <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z" /></svg>} label="Inicio" />
          <NavButton active={activeTab === 'budget'} onClick={() => setActiveTab('budget')} icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 3.055A9.001 9.001 0 1020.945 13H11V3.055z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.488 9H15V3.512A9.025 9.025 0 0120.488 9z" /></svg>} label="Plan" />
          <NavButton active={activeTab === 'chat'} onClick={() => setActiveTab('chat')} icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>} label="Chat AI" />
          <NavButton active={activeTab === 'academy'} onClick={() => setActiveTab('academy')} icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>} label="Aprender" />
        </div>
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1 transition-all px-4 py-2 rounded-2xl ${active ? 'text-indigo-600 bg-indigo-50/50 dark:bg-indigo-900/30' : 'text-slate-400 hover:text-slate-600 dark:hover:text-slate-300'}`}>
    {icon}
    <span className="text-[10px] font-bold uppercase tracking-wider">{label}</span>
