        <h2 className="text-2xl font-black italic uppercase mb-2">Examen de Certificación</h2>
        <p className="text-xs text-slate-500 uppercase font-bold mb-6">Valida tu camino al éxito financiero.</p>

        {quizStep === 'intro' && (
