const Academy: React.FC<{ profile: UserProfile, onUpdateProfile: (u: Partial<UserProfile>) => void, onCompleteLesson: (id: string, xp: number) => void, isDarkMode: boolean }> = ({ profile, onUpdateProfile, onCompleteLesson, isDarkMode }) => {
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);
  const [showTask, setShowTask] = useState(false);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [taskFeedback, setTaskFeedback] = useState<{ isCorrect: boolean, message: string } | null>(null);
  const [sessionStartTime, setSessionStartTime] = useState<number>(Date.now());

  const completedSet = new Set(profile.completedLessons);

  const handleStartLesson = (lesson: Lesson) => {
    if (profile.lives <= 0) {
      alert("¡No tienes vidas! Espera a que se recarguen.");
      return;
    }
    setActiveLesson(lesson);
    setShowTask(false);
    setSelectedOption(null);
    setTaskFeedback(null);
    setSessionStartTime(Date.now());
  };

  const handleAnswer = (idx: number) => {
    if (!activeLesson || taskFeedback) return;
    setSelectedOption(idx);
    const isCorrect = idx === activeLesson.task.correctIndex;

    if (isCorrect) {
      const timeBonus = Math.max(0, 50 - Math.floor((Date.now() - sessionStartTime) / 1000));
      setTaskFeedback({ isCorrect: true, message: `¡Excelente! +${activeLesson.xp + timeBonus} XP` });
      setTimeout(() => {
        onCompleteLesson(activeLesson.id, activeLesson.xp + timeBonus);
        setActiveLesson(null);
      }, 2000);
    } else {
      setTaskFeedback({ isCorrect: false, message: activeLesson.task.explanation });
      onUpdateProfile({ lives: profile.lives - 1 });
      if (profile.lives <= 1) {
        setTimeout(() => setActiveLesson(null), 3000);
      }
    }
  };

  return (
    <div className="space-y-8 pb-24 animate-in fade-in duration-500">
      <header className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-black italic uppercase tracking-tighter">Inversión Zcorpion</h2>
          <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Domina el mercado nivel a nivel</p>
        </div>
        <div className="flex items-center gap-4 bg-slate-100 dark:bg-slate-900 px-4 py-2 rounded-2xl border border-slate-200 dark:border-slate-800">
          <div className="flex items-center gap-1">
            <span className="text-rose-500 text-lg">❤️</span>
            <span className="font-black">{profile.lives}</span>
          </div>
          <div className="w-px h-4 bg-slate-300 dark:bg-slate-700" />
          <div className="flex items-center gap-1">
            <span className="text-indigo-500 text-lg">⭐</span>
            <span className="font-black">{profile.xp}</span>
          </div>
        </div>
      </header>

      {/* RUTA DEL MAPA */}
      <div className="relative flex flex-col items-center gap-12 py-10">
        <div className="absolute top-0 bottom-0 w-1 bg-slate-200 dark:bg-slate-800 -z-10" />
        {INVESTMENT_MAP.map((lesson, idx) => {
          const isCompleted = completedSet.has(lesson.id);
          const isUnlocked = idx === 0 || completedSet.has(INVESTMENT_MAP[idx - 1].id);
          const isCurrent = isUnlocked && !isCompleted;

          return (
            <div key={lesson.id} className="relative group">
              <button
                disabled={!isUnlocked}
                onClick={() => handleStartLesson(lesson)}
                className={`w-20 h-20 rounded-full border-4 flex items-center justify-center text-3xl transition-all duration-500 shadow-xl relative ${
                  isCompleted 
                    ? 'bg-emerald-500 border-emerald-300 text-white' 
                    : isCurrent 
                      ? 'bg-indigo-600 border-indigo-400 text-white animate-bounce ring-4 ring-indigo-500/30' 
                      : isUnlocked 
                        ? 'bg-white border-slate-200 text-slate-800 dark:bg-slate-800 dark:border-slate-700' 
                        : 'bg-slate-100 border-slate-200 text-slate-300 dark:bg-slate-900 dark:border-slate-800 grayscale'
                }`}
              >
                {lesson.icon}
                {isCompleted && (
                  <div className="absolute -top-1 -right-1 bg-white dark:bg-slate-900 rounded-full p-1 shadow-sm">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-emerald-500" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                    </svg>
                  </div>
                )}
              </button>
              <div className={`absolute left-24 top-1/2 -translate-y-1/2 whitespace-nowrap transition-all ${isUnlocked ? 'opacity-100' : 'opacity-30'}`}>
                <h4 className="font-black italic uppercase text-xs tracking-tight">{lesson.title}</h4>
                <p className="text-[8px] font-bold text-slate-500 uppercase">{lesson.xp} XP</p>
              </div>
            </div>
          );
        })}
      </div>

      {/* MODAL DE LECCIÓN ACTIVA */}
      {activeLesson && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-md animate-in fade-in zoom-in duration-300">
          <div className={`w-full max-w-lg rounded-[2.5rem] p-8 shadow-2xl relative transition-colors ${isDarkMode ? 'bg-slate-900 text-white' : 'bg-white text-slate-900'}`}>
            <button onClick={() => setActiveLesson(null)} className="absolute top-6 right-6 p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>

            {!showTask ? (
              <div className="space-y-6">
                <div className="text-6xl text-center">{activeLesson.icon}</div>
                <h3 className="text-2xl font-black italic uppercase text-center leading-tight">{activeLesson.title}</h3>
                <p className="text-sm leading-relaxed text-slate-600 dark:text-slate-400 font-medium bg-slate-50 dark:bg-slate-800 p-6 rounded-3xl border border-slate-100 dark:border-slate-700">
                  {activeLesson.content}
                </p>
                <button 
                  onClick={() => { setShowTask(true); setSessionStartTime(Date.now()); }}
                  className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl hover:bg-indigo-700 active:scale-95 transition-all"
                >
                  Entendido, Iniciar Tarea
                </button>
              </div>
            ) : (
              <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-indigo-500">
                  <span>Misión Interactiva</span>
                  <span>XP: {activeLesson.xp}</span>
                </div>
                <h3 className="text-lg font-bold leading-tight">{activeLesson.task.question}</h3>
                <div className="grid grid-cols-1 gap-3">
                  {activeLesson.task.options.map((option, idx) => (
                    <button
                      key={idx}
                      disabled={!!taskFeedback}
                      onClick={() => handleAnswer(idx)}
                      className={`w-full p-4 text-left rounded-2xl border-2 font-bold text-sm transition-all ${
                        selectedOption === idx 
                          ? (idx === activeLesson.task.correctIndex ? 'bg-emerald-500/10 border-emerald-500' : 'bg-rose-500/10 border-rose-500')
                          : isDarkMode ? 'bg-slate-800 border-slate-700 hover:border-indigo-500' : 'bg-slate-50 border-slate-100 hover:border-indigo-400'
                      }`}
                    >
                      {option}
                    </button>
                  ))}
                </div>

                {taskFeedback && (
                  <div className={`p-4 rounded-2xl border animate-in zoom-in ${
                    taskFeedback.isCorrect ? 'bg-emerald-500/10 border-emerald-500 text-emerald-600' : 'bg-rose-500/10 border-rose-500 text-rose-600'
                  }`}>
                    <p className="text-xs font-black uppercase mb-1">{taskFeedback.isCorrect ? '✓ Correcto' : '✗ Error (-1 vida)'}</p>
                    <p className="text-[11px] leading-tight font-medium">{taskFeedback.message}</p>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      )}

      {/* SECCIÓN DE RESUMEN DE PUNTOS */}
      <section className={`p-8 rounded-[2rem] border shadow-xl relative transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <h2 className="text-xl font-black italic uppercase mb-4">Estadísticas de Aprendizaje</h2>
        <div className="grid grid-cols-2 gap-4">
          <div className="p-4 rounded-2xl bg-indigo-500/10 border border-indigo-500/20 text-center">
            <p className="text-2xl font-black text-indigo-500">{profile.completedLessons.length}</p>
            <p className="text-[9px] font-black uppercase tracking-widest text-slate-400">Lecciones Dominadas</p>
          </div>
          <div className="p-4 rounded-2xl bg-amber-500/10 border border-amber-500/20 text-center">
            <p className="text-2xl font-black text-amber-500">{Math.floor(profile.xp / 100)}</p>
            <p className="text-[9px] font-black uppercase tracking-widest text-slate-400">Nivel de Sabiduría</p>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Academy;

