const Academy: React.FC<{ 
  profile: UserProfile, 
  onUpdateProfile: (u: Partial<UserProfile>) => void, 
  onCompleteLesson: (id: string, xp: number) => void, 
  isDarkMode: boolean 
}> = ({ profile, onUpdateProfile, onCompleteLesson, isDarkMode }) => {
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);
  const [currentStepIdx, setCurrentStepIdx] = useState(0);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [stepFeedback, setStepFeedback] = useState<{ isCorrect: boolean, message: string } | null>(null);
  const [timer, setTimer] = useState(30);
  const [accumulatedXP, setAccumulatedXP] = useState(0);
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  const completedSet = new Set(profile.completedLessons);

  // Iniciar lección
  const startLesson = (lesson: Lesson) => {
    if (profile.lives <= 0) return;
    setActiveLesson(lesson);
    setCurrentStepIdx(0);
    setSelectedOption(null);
    setStepFeedback(null);
    setTimer(30);
    setAccumulatedXP(0);
    startTimer();
  };

  const startTimer = () => {
    if (timerRef.current) clearInterval(timerRef.current);
    setTimer(30);
    timerRef.current = setInterval(() => {
      setTimer(t => (t > 0 ? t - 1 : 0));
    }, 1000);
  };

  const handleNextStep = () => {
    if (!activeLesson) return;
    if (currentStepIdx < activeLesson.steps.length - 1) {
      setCurrentStepIdx(currentStepIdx + 1);
      setSelectedOption(null);
      setStepFeedback(null);
      startTimer();
    } else {
      // Finalizar lección
      if (timerRef.current) clearInterval(timerRef.current);
      const totalXP = activeLesson.xp + accumulatedXP;
      onCompleteLesson(activeLesson.id, totalXP);
      setActiveLesson(null);
    }
  };

  const handleAnswer = (idx: number) => {
    if (!activeLesson || stepFeedback) return;
    const step = activeLesson.steps[currentStepIdx];
    setSelectedOption(idx);

    if (idx === step.correctIndex) {
      const timeBonus = timer > 15 ? 20 : 10;
      setAccumulatedXP(prev => prev + timeBonus);
      setStepFeedback({ isCorrect: true, message: `¡Correcto! Bonus de tiempo: +${timeBonus} XP` });
      setTimeout(handleNextStep, 1500);
    } else {
      setStepFeedback({ isCorrect: false, message: '¡Uh oh! Perdiste una vida. Revisa el contenido anterior.' });
      onUpdateProfile({ lives: profile.lives - 1 });
      if (profile.lives <= 1) {
        setTimeout(() => setActiveLesson(null), 2000);
      }
    }
  };

  // Renderizado del Mapa Sinuoso
  const renderMap = () => {
    return (
      <div className="relative flex flex-col items-center gap-16 py-20 px-4">
        {/* Línea SVG de fondo */}
        <svg className="absolute top-0 left-1/2 -translate-x-1/2 w-64 h-full pointer-events-none opacity-20" viewBox="0 0 100 800" preserveAspectRatio="none">
          <path 
            d="M50,0 Q80,100 50,200 T50,400 Q20,500 50,600 T50,800" 
            fill="none" 
            stroke={isDarkMode ? "#6366f1" : "#4f46e5"} 
            strokeWidth="4" 
            strokeDasharray="10 10" 
          />
        </svg>

        {INVESTMENT_MAP.map((lesson, idx) => {
          const isCompleted = completedSet.has(lesson.id);
          const isUnlocked = idx === 0 || completedSet.has(INVESTMENT_MAP[idx - 1].id);
          const isCurrent = isUnlocked && !isCompleted;

          // Efecto de zigzag
          const offset = idx % 2 === 0 ? '-translate-x-12' : 'translate-x-12';

          return (
            <div key={lesson.id} className={`relative z-10 flex flex-col items-center group transition-all duration-500 ${offset}`}>
               {/* Etiqueta de Mundo */}
               {(idx === 0 || INVESTMENT_MAP[idx-1].world !== lesson.world) && (
                 <div className="absolute -top-12 left-1/2 -translate-x-1/2 whitespace-nowrap">
                   <span className="bg-slate-800 text-white text-[9px] font-black uppercase tracking-[0.2em] px-4 py-1.5 rounded-full border border-slate-700 shadow-xl">
                     Mundo: {lesson.world}
                   </span>
                 </div>
               )}

              <button
                disabled={!isUnlocked}
                onClick={() => startLesson(lesson)}
                className={`w-24 h-24 rounded-[2rem] border-4 flex items-center justify-center text-4xl transition-all duration-500 shadow-2xl relative ${
                  isCompleted 
                    ? 'bg-emerald-500 border-emerald-300 text-white' 
                    : isCurrent 
                      ? 'bg-indigo-600 border-indigo-400 text-white animate-pulse ring-8 ring-indigo-500/20' 
                      : isUnlocked 
                        ? 'bg-white border-slate-200 text-slate-800 dark:bg-slate-800 dark:border-slate-700' 
                        : 'bg-slate-100 border-slate-200 text-slate-300 dark:bg-slate-900 dark:border-slate-800 grayscale'
                }`}
              >
                {isUnlocked ? lesson.icon : '🔒'}
                {isCompleted && (
                  <div className="absolute -bottom-2 -right-2 bg-emerald-500 text-white rounded-full p-1.5 shadow-lg border-2 border-white dark:border-slate-900">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                    </svg>
                  </div>
                )}
              </button>

              <div className={`mt-3 text-center transition-all ${isUnlocked ? 'opacity-100' : 'opacity-40'}`}>
                <h4 className="font-black italic uppercase text-[11px] tracking-tight">{lesson.title}</h4>
                <div className="flex items-center justify-center gap-1 mt-1">
                  <span className="text-indigo-500 text-[9px] font-black">{lesson.xp} XP</span>
                  <div className="w-1 h-1 rounded-full bg-slate-300" />
                  <span className="text-slate-400 text-[9px] font-bold uppercase">{lesson.steps.length} Pasos</span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className={`space-y-8 pb-32 min-h-screen transition-colors duration-500 ${isDarkMode ? 'bg-slate-950' : 'bg-slate-50'}`}>
      {/* Header Estético */}
      <header className="px-6 py-8 flex items-center justify-between sticky top-0 z-50 backdrop-blur-md bg-white/10">
        <div>
          <h2 className="text-4xl font-black italic uppercase tracking-tighter text-indigo-600 dark:text-indigo-400">Z-Academy</h2>
          <div className="flex items-center gap-2 mt-1">
            <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Maestría en Inversiones</p>
          </div>
        </div>

        <div className="flex items-center gap-4 bg-white/80 dark:bg-slate-900/80 px-4 py-2 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-xl">
          <div className="flex items-center gap-2">
            <span className="text-rose-500 animate-pulse">❤️</span>
            <span className="font-black text-lg">{profile.lives}</span>
          </div>
          <div className="w-px h-6 bg-slate-200 dark:bg-slate-700" />
          <div className="flex items-center gap-2">
            <span className="text-indigo-500">⭐</span>
            <span className="font-black text-lg">{profile.xp}</span>
          </div>
        </div>
      </header>

      {renderMap()}

      {/* OVERLAY DE LECCIÓN - MODO INMERSIVO */}
      {activeLesson && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-0 md:p-6 bg-slate-950/95 backdrop-blur-2xl animate-in fade-in duration-300">
          <div className={`w-full h-full md:h-auto max-w-2xl md:rounded-[3rem] overflow-hidden flex flex-col shadow-2xl relative transition-colors ${isDarkMode ? 'bg-slate-900' : 'bg-white'}`}>

            {/* Barra de Progreso Superior */}
            <div className="h-2 w-full bg-slate-100 dark:bg-slate-800">
              <div 
                className="h-full bg-indigo-600 transition-all duration-500 ease-out"
                style={{ width: `${((currentStepIdx + 1) / activeLesson.steps.length) * 100}%` }}
              />
            </div>

            <button onClick={() => setActiveLesson(null)} className="absolute top-6 right-6 p-3 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full z-10">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>

            <div className="flex-1 p-8 md:p-12 overflow-y-auto flex flex-col">
              <div className="mb-8 flex justify-between items-center">
                <span className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500">Paso {currentStepIdx + 1} de {activeLesson.steps.length}</span>
                <div className="flex items-center gap-2">
                   <div className={`w-10 h-10 rounded-full border-2 flex items-center justify-center font-black text-xs ${timer < 10 ? 'border-rose-500 text-rose-500 animate-pulse' : 'border-indigo-500 text-indigo-500'}`}>
                     {timer}
                   </div>
                </div>
              </div>

              {/* Contenido Dinámico del Paso */}
              <div className="flex-1 space-y-8 animate-in slide-in-from-bottom-4 duration-500">
                <div className="flex items-center gap-4">
                  <div className="text-5xl bg-slate-100 dark:bg-slate-800 p-4 rounded-[1.5rem]">{activeLesson.icon}</div>
                  <h3 className="text-2xl md:text-3xl font-black italic uppercase leading-tight">{activeLesson.steps[currentStepIdx].title}</h3>
                </div>

                <div className="prose dark:prose-invert">
                  <p className="text-lg md:text-xl leading-relaxed text-slate-600 dark:text-slate-300 font-medium">
                    {activeLesson.steps[currentStepIdx].content}
                  </p>
                </div>

                {activeLesson.steps[currentStepIdx].type === 'info' && (
                  <button 
                    onClick={handleNextStep}
                    className="w-full mt-12 bg-indigo-600 text-white py-5 rounded-2xl font-black uppercase tracking-widest shadow-2xl hover:bg-indigo-700 active:scale-95 transition-all flex items-center justify-center gap-2 group"
                  >
