            strokeDasharray="10 10" 
          />
        </svg>

        {INVESTMENT_MAP.map((lesson, idx) => {
          const isCompleted = completedSet.has(lesson.id);
          const isUnlocked = idx === 0 || completedSet.has(INVESTMENT_MAP[idx - 1].id);
