                className={`w-24 h-24 rounded-[2rem] border-4 flex items-center justify-center text-4xl transition-all duration-500 shadow-2xl relative ${
                  isCompleted 
                    ? 'bg-emerald-500 border-emerald-300 text-white' 
                    : isCurrent 
                      ? 'bg-indigo-600 border-indigo-400 text-white animate-pulse ring-8 ring-indigo-500/20' 
