          </div>
          <div className="w-px h-6 bg-slate-200 dark:bg-slate-700" />
          <div className="flex items-center gap-2">
            <span className="text-indigo-500">⭐</span>
            <span className="font-black text-lg">{profile.xp}</span>
          </div>
        </div>
      </header>

      {renderMap()}

      {/* OVERLAY DE LECCIÓN - MODO INMERSIVO */}
      {activeLesson && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-0 md:p-6 bg-slate-950/95 backdrop-blur-2xl animate-in fade-in duration-300">
          <div className={`w-full h-full md:h-auto max-w-2xl md:rounded-[3rem] overflow-hidden flex flex-col shadow-2xl relative transition-colors ${isDarkMode ? 'bg-slate-900' : 'bg-white'}`}>

