                </div>

                {activeLesson.steps[currentStepIdx].type === 'info' && (
                  <button 
                    onClick={handleNextStep}
                    className="w-full mt-12 bg-indigo-600 text-white py-5 rounded-2xl font-black uppercase tracking-widest shadow-2xl hover:bg-indigo-700 active:scale-95 transition-all flex items-center justify-center gap-2 group"
                  >
                    Continuar <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 group-hover:translate-x-1 transition-transform" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10.293 3.293a1 1 0 011.414 0l6 6a1 1 0 010 1.414l-6 6a1 1 0 01-1.414-1.414L14.586 11H3a1 1 0 110-2h11.586l-4.293-4.293a1 1 0 010-1.414z" clipRule="evenodd" /></svg>
                  </button>
                )}

                {activeLesson.steps[currentStepIdx].type === 'quiz' && (
                  <div className="space-y-4 pt-6">
                    <p className="text-sm font-black uppercase text-indigo-500 tracking-wider">{activeLesson.steps[currentStepIdx].question}</p>
                    <div className="grid grid-cols-1 gap-3">
                      {activeLesson.steps[currentStepIdx].options?.map((opt, i) => (
                        <button 
                          key={i}
                          disabled={!!stepFeedback}
                          onClick={() => handleAnswer(i)}
                          className={`w-full p-5 text-left rounded-2xl border-2 font-bold text-base transition-all flex justify-between items-center ${
                            selectedOption === i 
                              ? (i === activeLesson.steps[currentStepIdx].correctIndex ? 'bg-emerald-500 border-emerald-400 text-white' : 'bg-rose-500 border-rose-400 text-white')
