                          }`}
                        >
                          {opt}
                          {selectedOption === i && (
                            <span>{i === activeLesson.steps[currentStepIdx].correctIndex ? '✓' : '✗'}</span>
                          )}
                        </button>
                      ))}
                    </div>
                  </div>
                )}

                {activeLesson.steps[currentStepIdx].type === 'practice' && (
                  <div className="bg-indigo-500/10 p-8 rounded-3xl border-2 border-indigo-500/20 text-center">
                    <div className="text-4xl mb-4">🚀</div>
                    <p className="text-sm italic font-bold text-indigo-600 dark:text-indigo-400">"El conocimiento sin acción es solo información. ¡Mira este ejemplo práctico!"</p>
                    <button 
                      onClick={handleNextStep}
                      className="mt-6 bg-indigo-600 text-white px-8 py-3 rounded-xl font-black uppercase text-xs"
                    >
                      Lo tengo, siguiente reto
