const Academy: React.FC<{ 
  profile: UserProfile, 
  onUpdateProfile: (u: Partial<UserProfile>) => void, 
  onCompleteLesson: (id: string, xp: number) => void, 
  isDarkMode: boolean 
}> = ({ profile, onUpdateProfile, onCompleteLesson, isDarkMode }) => {
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);
  const [currentStepIdx, setCurrentStepIdx] = useState(0);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [stepFeedback, setStepFeedback] = useState<{ isCorrect: boolean, message: string } | null>(null);
  const [timer, setTimer] = useState(30);
  const [accumulatedXP, setAccumulatedXP] = useState(0);
  const timerRef = useRef<any>(null);

  const completedSet = new Set(profile.completedLessons);

  const startLesson = (lesson: Lesson) => {
    if (profile.lives <= 0) return;
    setActiveLesson(lesson);
    setCurrentStepIdx(0);
    setSelectedOption(null);
    setStepFeedback(null);
    setTimer(30);
    setAccumulatedXP(0);
    startTimer();
  };

  const startTimer = () => {
    if (timerRef.current) clearInterval(timerRef.current);
    setTimer(30);
    timerRef.current = setInterval(() => {
      setTimer(t => (t > 0 ? t - 1 : 0));
    }, 1000);
  };

  const handleNextStep = () => {
    if (!activeLesson) return;
    if (currentStepIdx < activeLesson.steps.length - 1) {
      setCurrentStepIdx(currentStepIdx + 1);
      setSelectedOption(null);
      setStepFeedback(null);
      startTimer();
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
      const totalXP = activeLesson.xp + accumulatedXP;
      onCompleteLesson(activeLesson.id, totalXP);
      setActiveLesson(null);
    }
  };

  const handleAnswer = (idx: number) => {
    if (!activeLesson || stepFeedback) return;
    const step = activeLesson.steps[currentStepIdx];
    setSelectedOption(idx);

    if (idx === step.correctIndex) {
      const timeBonus = timer > 15 ? 20 : 10;
      setAccumulatedXP(prev => prev + timeBonus);
      setStepFeedback({ isCorrect: true, message: `¡Correcto! Bonus: +${timeBonus} XP` });
      setTimeout(handleNextStep, 1500);
    } else {
      setStepFeedback({ isCorrect: false, message: '¡Error! Pierdes 1 vida.' });
      onUpdateProfile({ lives: profile.lives - 1 });
      if (profile.lives <= 1) {
        setTimeout(() => setActiveLesson(null), 2000);
      }
    }
  };

  const renderMap = () => {
    return (
      <div className="relative flex flex-col items-center gap-24 py-24 px-4 overflow-hidden">
        <svg className="absolute top-0 left-1/2 -translate-x-1/2 w-64 h-full pointer-events-none opacity-10" viewBox="0 0 100 2500" preserveAspectRatio="none">
          <path 
            d="M50,0 Q80,200 50,400 T50,800 Q20,1000 50,1200 T50,1600 Q80,1800 50,2000 T50,2400" 
            fill="none" 
            stroke={isDarkMode ? "#6366f1" : "#4f46e5"} 
            strokeWidth="3" 
            strokeDasharray="12 12" 
          />
        </svg>

        {INVESTMENT_MAP.map((lesson, idx) => {
          const isCompleted = completedSet.has(lesson.id);
          const isUnlocked = idx === 0 || completedSet.has(INVESTMENT_MAP[idx - 1].id);
          const isCurrent = isUnlocked && !isCompleted;
          const offset = idx % 2 === 0 ? '-translate-x-14 md:-translate-x-20' : 'translate-x-14 md:translate-x-20';

          return (
            <div key={lesson.id} className={`relative z-10 flex flex-col items-center group transition-all duration-700 ${offset}`}>
               {(idx === 0 || INVESTMENT_MAP[idx-1].world !== lesson.world) && (
                 <div className="absolute -top-16 left-1/2 -translate-x-1/2 whitespace-nowrap">
                   <div className="flex flex-col items-center gap-1">
                     <span className="bg-indigo-600 text-white text-[8px] font-black uppercase tracking-[0.3em] px-5 py-2 rounded-full shadow-2xl border border-white/20">
                       Mundo: {lesson.world}
                     </span>
                     <div className="w-0.5 h-6 bg-indigo-500/30" />
                   </div>
                 </div>
               )}

              <button
                disabled={!isUnlocked}
                onClick={() => startLesson(lesson)}
                className={`w-28 h-28 rounded-[2.5rem] border-4 flex items-center justify-center text-5xl transition-all duration-500 shadow-2xl relative ${
                  isCompleted 
                    ? 'bg-emerald-500 border-emerald-300 text-white rotate-12' 
                    : isCurrent 
                      ? 'bg-indigo-600 border-indigo-400 text-white animate-bounce ring-8 ring-indigo-500/20' 
                      : isUnlocked 
                        ? 'bg-white border-slate-200 text-slate-800 dark:bg-slate-800 dark:border-slate-700' 
                        : 'bg-slate-100 border-slate-200 text-slate-300 dark:bg-slate-900 dark:border-slate-800 grayscale'
                }`}
              >
                {isUnlocked ? (isCompleted ? '🏆' : lesson.icon) : '🔒'}
                {isCompleted && (
                  <div className="absolute -bottom-2 -right-2 bg-emerald-400 text-white rounded-full p-2 shadow-lg border-2 border-white dark:border-slate-900 scale-110">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                  </div>
                )}
              </button>

              <div className={`mt-4 text-center transition-all ${isUnlocked ? 'opacity-100 scale-100' : 'opacity-40 scale-90'}`}>
                <h4 className="font-black italic uppercase text-xs tracking-tight">{lesson.title}</h4>
                <div className="flex items-center justify-center gap-2 mt-1">
                  <span className="text-indigo-500 text-[10px] font-black">{lesson.xp} XP</span>
                  <div className="w-1 h-1 rounded-full bg-slate-300" />
                  <span className="text-slate-400 text-[10px] font-bold uppercase">{lesson.steps.length} Pasos</span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className={`space-y-8 pb-32 min-h-screen transition-all duration-700 ${isDarkMode ? 'bg-slate-950' : 'bg-slate-50'}`}>
      <header className="px-6 py-10 flex items-center justify-between sticky top-0 z-50 backdrop-blur-xl bg-white/5 border-b border-white/5">
        <div>
          <h2 className="text-4xl font-black italic uppercase tracking-tighter bg-gradient-to-r from-indigo-500 to-emerald-500 bg-clip-text text-transparent">Academy</h2>
          <div className="flex items-center gap-2 mt-1">
            <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse" />
            <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Maestría Financiera Pro</p>
          </div>
        </div>

        <div className="flex items-center gap-4 bg-white/80 dark:bg-slate-900/80 px-5 py-3 rounded-full border border-white/10 shadow-2xl">
          <div className="flex items-center gap-2">
            <span className="text-rose-500 text-xl">❤️</span>
            <span className="font-black text-xl">{profile.lives}</span>
          </div>
          <div className="w-px h-6 bg-slate-200 dark:bg-slate-700" />
          <div className="flex items-center gap-2">
            <span className="text-indigo-500 text-xl">⭐</span>
            <span className="font-black text-xl">{profile.xp}</span>
          </div>
        </div>
      </header>

      {renderMap()}

      {activeLesson && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-0 md:p-8 bg-slate-950/98 backdrop-blur-3xl animate-in fade-in duration-500">
          <div className={`w-full h-full md:h-auto max-w-3xl md:rounded-[4rem] overflow-hidden flex flex-col shadow-2xl relative transition-all duration-500 ${isDarkMode ? 'bg-slate-900' : 'bg-white'}`}>

            <div className="h-3 w-full bg-slate-100 dark:bg-slate-800">
              <div 
                className="h-full bg-gradient-to-r from-indigo-600 to-emerald-500 transition-all duration-700 ease-out shadow-[0_0_15px_rgba(99,102,241,0.5)]"
                style={{ width: `${((currentStepIdx + 1) / activeLesson.steps.length) * 100}%` }}
              />
            </div>

            <button onClick={() => setActiveLesson(null)} className="absolute top-8 right-8 p-4 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full z-10 transition-all">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>

            <div className="flex-1 p-10 md:p-16 overflow-y-auto flex flex-col items-center text-center">
              <div className="mb-10 flex justify-between items-center w-full">
                <span className="text-[11px] font-black uppercase tracking-[0.4em] text-indigo-500 bg-indigo-500/10 px-4 py-1.5 rounded-full">Paso {currentStepIdx + 1} / {activeLesson.steps.length}</span>
                <div className={`w-14 h-14 rounded-full border-4 flex items-center justify-center font-black text-lg ${timer < 10 ? 'border-rose-500 text-rose-500 animate-pulse' : 'border-indigo-500 text-indigo-500'}`}>
                  {timer}
                </div>
              </div>

              <div className="flex-1 space-y-10 animate-in slide-in-from-bottom-8 duration-700 w-full max-w-lg">
                <div className="text-8xl bg-slate-100 dark:bg-slate-800 p-8 rounded-[3rem] inline-block shadow-inner">{activeLesson.icon}</div>
                <h3 className="text-3xl md:text-5xl font-black italic uppercase leading-tight tracking-tighter">{activeLesson.steps[currentStepIdx].title}</h3>

                <p className="text-xl md:text-2xl leading-relaxed text-slate-600 dark:text-slate-300 font-medium">
                  {activeLesson.steps[currentStepIdx].content}
                </p>

                {activeLesson.steps[currentStepIdx].type === 'info' && (
                  <button 
                    onClick={handleNextStep}
                    className="w-full mt-12 bg-indigo-600 text-white py-6 rounded-[2rem] font-black uppercase tracking-widest shadow-2xl hover:bg-indigo-700 hover:scale-105 active:scale-95 transition-all flex items-center justify-center gap-4 group"
                  >
                    Entendido <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 group-hover:translate-x-2 transition-transform" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10.293 3.293a1 1 0 011.414 0l6 6a1 1 0 010 1.414l-6 6a1 1 0 01-1.414-1.414L14.586 11H3a1 1 0 110-2h11.586l-4.293-4.293a1 1 0 010-1.414z" clipRule="evenodd" /></svg>
                  </button>
                )}

                {activeLesson.steps[currentStepIdx].type === 'quiz' && (
                  <div className="space-y-5 pt-8 w-full">
                    <p className="text-lg font-black uppercase text-indigo-500 tracking-tight">{activeLesson.steps[currentStepIdx].question}</p>
                    <div className="grid grid-cols-1 gap-4">
                      {activeLesson.steps[currentStepIdx].options?.map((opt, i) => (
                        <button 
                          key={i}
                          disabled={!!stepFeedback}
                          onClick={() => handleAnswer(i)}
                          className={`w-full p-6 text-left rounded-[1.5rem] border-3 font-bold text-lg transition-all flex justify-between items-center ${
                            selectedOption === i 
                              ? (i === activeLesson.steps[currentStepIdx].correctIndex ? 'bg-emerald-500 border-emerald-400 text-white shadow-emerald-500/40' : 'bg-rose-500 border-rose-400 text-white shadow-rose-500/40')
                              : isDarkMode ? 'bg-slate-800 border-slate-700 hover:border-indigo-500' : 'bg-slate-50 border-slate-200 hover:border-indigo-400'
                          } shadow-lg`}
                        >
                          {opt}
                          {selectedOption === i && (
                            <span className="text-2xl">{i === activeLesson.steps[currentStepIdx].correctIndex ? '✓' : '✗'}</span>
                          )}
                        </button>
                      ))}
                    </div>
                  </div>
                )}

                {activeLesson.steps[currentStepIdx].type === 'practice' && (
                  <div className="bg-gradient-to-br from-indigo-500/20 to-emerald-500/20 p-10 rounded-[3rem] border-2 border-white/10 text-center shadow-2xl">
                    <div className="text-6xl mb-6">🚀 Misión Práctica</div>
                    <p className="text-lg italic font-bold text-indigo-600 dark:text-indigo-400 mb-8">"Pon en práctica lo aprendido para asegurar tu racha y tus puntos."</p>
                    <button 
                      onClick={handleNextStep}
                      className="bg-white dark:bg-slate-900 text-indigo-600 dark:text-indigo-400 px-10 py-4 rounded-2xl font-black uppercase text-sm shadow-xl hover:scale-105 active:scale-95 transition-all"
                    >
                      ¡Misión Cumplida!
                    </button>
                  </div>
                )}

                {stepFeedback && (
                  <div className={`p-6 rounded-[2rem] border-3 animate-bounce mt-10 shadow-2xl ${
                    stepFeedback.isCorrect ? 'bg-emerald-500/10 border-emerald-500 text-emerald-600' : 'bg-rose-500/10 border-rose-500 text-rose-600'
                  }`}>
                    <p className="font-black text-xl uppercase tracking-tighter">{stepFeedback.isCorrect ? '¡Impresionante!' : '¡Analiza de nuevo!'}</p>
                    <p className="text-sm font-bold opacity-80 mt-1">{stepFeedback.message}</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Academy;

export enum Category {
  NEEDS = 'NEEDS',
  WANTS = 'WANTS',
  SAVINGS = 'SAVINGS'
}

export enum Frequency {
  MONTHLY = 'MONTHLY',
  BIWEEKLY = 'BIWEEKLY',
  WEEKLY = 'WEEKLY'
}

export interface ReminderConfig {
  enabled: boolean;
  time: string; // HH:mm
  frequency: 'DAILY' | 'WEEKLY';
  customMessage?: string;
}

export interface Expense {
  id: string;
  amount: number;
  category: Category;
  description: string;
  date: string;
  isFixed?: boolean;
  frequency?: Frequency;
}

export interface UserProfile {
  username: string;
  income: number;
  frequency: Frequency;
  currency: string;
  streak: number;
  lastLoginDate: string;
  lastStreakDate?: string;
  reminders?: ReminderConfig;
  // Gamificación
  xp: number;
  lives: number;
  lastLifeRegenTime?: string; // ISO string
  completedLessons: string[];
  // Social
  friends: string[];
  friendRequests: string[];
}

export interface BudgetSplit {
  needs: number;
  wants: number;
  savings: number;
}

export interface SavingsGoal {
  id: string;
  name: string;
  targetAmount: number;
  currentAmount: number;
}

export interface SocialMessage {
  id: string;
  sender: string;
  text: string;
  timestamp: string;
}

import React, { useState, useEffect } from 'react';
import { UserProfile, Expense, Frequency, Category, SavingsGoal } from './types';
import Onboarding from './components/Onboarding';
import Dashboard from './components/Dashboard';
import BudgetDetails from './components/BudgetDetails';
import AIChat from './components/AIChat';
import Academy from './components/Academy';
import Settings from './components/Settings';
import Social from './components/Social';
import ProfilePage from './components/ProfilePage';
import Tutorial from './components/Tutorial';
import { FREQUENCY_LABELS, CURRENCY_SYMBOLS } from './constants';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [goals, setGoals] = useState<SavingsGoal[]>([]);
  const [showTutorial, setShowTutorial] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'budget' | 'chat' | 'academy' | 'social' | 'profile'>('dashboard');
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    return localStorage.getItem('finanza_dark_mode') === 'true';
  });

  useEffect(() => {
    const savedProfile = localStorage.getItem('finanza_profile');
    const savedExpenses = localStorage.getItem('finanza_expenses');
    const savedGoals = localStorage.getItem('finanza_goals');
    const hasSeenTutorial = localStorage.getItem('finanza_tutorial_seen');

    let currentProfile: UserProfile | null = savedProfile ? JSON.parse(savedProfile) : null;
    const currentExpenses: Expense[] = savedExpenses ? JSON.parse(savedExpenses) : [];

    if (currentProfile) {
      if (!hasSeenTutorial) setShowTutorial(true);

      // Lógica de Racha Diaria
      const today = new Date();
      today.setHours(0, 0, 0, 0);

      if (currentProfile.lastStreakDate) {
        const lastStreak = new Date(currentProfile.lastStreakDate);
        lastStreak.setHours(0, 0, 0, 0);
        const diffDays = Math.floor((today.getTime() - lastStreak.getTime()) / (1000 * 3600 * 24));
        if (diffDays > 1) currentProfile.streak = 0;
      }

      // Inicializar campos nuevos
      if (currentProfile.xp === undefined) currentProfile.xp = 0;
      if (currentProfile.lives === undefined) currentProfile.lives = 5;
      if (currentProfile.completedLessons === undefined) currentProfile.completedLessons = [];
      if (currentProfile.friends === undefined) currentProfile.friends = [];
      if (currentProfile.friendRequests === undefined) currentProfile.friendRequests = ['User_01', 'SmartSaver_99'];

      // Lógica de regeneración de vidas (1 cada 30 min)
      if (currentProfile.lives < 5) {
        const lastRegen = currentProfile.lastLifeRegenTime ? new Date(currentProfile.lastLifeRegenTime) : new Date();
        const now = new Date();
        const diffMinutes = Math.floor((now.getTime() - lastRegen.getTime()) / (1000 * 60));
        const livesToAdd = Math.floor(diffMinutes / 30);

        if (livesToAdd > 0) {
          currentProfile.lives = Math.min(5, currentProfile.lives + livesToAdd);
          currentProfile.lastLifeRegenTime = now.toISOString();
        }
      } else {
        currentProfile.lastLifeRegenTime = new Date().toISOString();
      }

      currentProfile.lastLoginDate = new Date().toISOString();
      setProfile(currentProfile);
    }

    if (savedExpenses) setExpenses(currentExpenses);
    if (savedGoals) setGoals(JSON.parse(savedGoals));
  }, []);

  useEffect(() => {
    if (profile) localStorage.setItem('finanza_profile', JSON.stringify(profile));
    if (expenses.length >= 0) localStorage.setItem('finanza_expenses', JSON.stringify(expenses));
    if (goals.length >= 0) localStorage.setItem('finanza_goals', JSON.stringify(goals));
    localStorage.setItem('finanza_dark_mode', isDarkMode.toString());
  }, [profile, expenses, goals, isDarkMode]);

  const updateStreak = (currentProfile: UserProfile) => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    let newStreak = currentProfile.streak;
    let newLastStreakDate = currentProfile.lastStreakDate;

    if (!currentProfile.lastStreakDate) {
      newStreak = 1;
      newLastStreakDate = today.toISOString();
    } else {
      const lastStreak = new Date(currentProfile.lastStreakDate);
      lastStreak.setHours(0, 0, 0, 0);
      const diffDays = Math.floor((today.getTime() - lastStreak.getTime()) / (1000 * 3600 * 24));

      if (diffDays === 1) {
        newStreak += 1;
        newLastStreakDate = today.toISOString();
      } else if (diffDays > 1) {
        newStreak = 1;
        newLastStreakDate = today.toISOString();
      }
    }
    return { streak: newStreak, lastStreakDate: newLastStreakDate };
  };

  const addExpense = (amount: number, category: Category, description: string, isFixed: boolean, frequency?: Frequency) => {
    if (!profile) return;
    const newExpense: Expense = {
      id: Math.random().toString(36).substr(2, 9),
      amount, category, description, isFixed,
      frequency: isFixed ? (frequency || profile.frequency) : undefined,
      date: new Date().toISOString()
    };
    setExpenses([...expenses, newExpense]);
    const streakUpdate = updateStreak(profile);
    setProfile({ ...profile, ...streakUpdate });
  };

  const completeLesson = (lessonId: string, xpGained: number) => {
    if (!profile) return;
    const streakUpdate = updateStreak(profile);
    const newCompleted = [...new Set([...profile.completedLessons, lessonId])];
    setProfile({ 
      ...profile, 
      ...streakUpdate, 
      xp: profile.xp + xpGained, 
      completedLessons: newCompleted 
    });
  };

  const handleUpdateProfile = (updates: Partial<UserProfile>) => { 
    if (profile) {
      const newProfile = { ...profile, ...updates };
      // Controlar límite de vidas
      if (newProfile.lives > 5) newProfile.lives = 5;
      if (newProfile.lives < 5 && profile.lives === 5) {
        newProfile.lastLifeRegenTime = new Date().toISOString();
      }
      setProfile(newProfile);
    }
  };

  const deleteExpense = (id: string) => setExpenses(expenses.filter(e => e.id !== id));
  const updateGoals = (newGoals: SavingsGoal[]) => setGoals(newGoals);
  const logout = () => { localStorage.clear(); setProfile(null); setExpenses([]); setGoals([]); setActiveTab('dashboard'); };

  if (!profile) return <Onboarding onComplete={(u, i, f, c) => {
    const p: UserProfile = { 
      username: u, income: i, frequency: f, currency: c, streak: 0, xp: 0, lives: 5, completedLessons: [],
      lastLoginDate: new Date().toISOString(), lastStreakDate: undefined,
      lastLifeRegenTime: new Date().toISOString(), friends: [], friendRequests: []
    };
    setProfile(p);
    setShowTutorial(true);
  }} />;

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-300 ${isDarkMode ? 'dark bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      {showTutorial && <Tutorial onComplete={() => { setShowTutorial(false); localStorage.setItem('finanza_tutorial_seen', 'true'); }} isDarkMode={isDarkMode} />}

      <header className={`border-b sticky top-0 z-30 px-6 py-4 flex items-center justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800 shadow-xl' : 'bg-white border-slate-100 shadow-sm'}`}>
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-xs">ZC</div>
          <h1 className="text-xl font-black tracking-tight italic uppercase">ZCORPION</h1>
        </div>
        <div className="flex items-center gap-3">
           <div className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 px-2 py-1 rounded-lg">
              <span className="text-xs text-rose-500">❤️</span>
              <span className="text-xs font-black">{profile.lives}</span>
           </div>
           <button onClick={() => setActiveTab('profile')} className={`p-2 rounded-xl border-2 transition-all ${isDarkMode ? 'bg-slate-800 border-indigo-900' : 'bg-slate-50 border-indigo-50'}`}>
              <div className="w-4 h-4 rounded-full bg-indigo-500 overflow-hidden">
                <div className="w-full h-full flex items-center justify-center text-[8px] text-white font-bold">
                  {profile.username[0].toUpperCase()}
                </div>
              </div>
           </button>
        </div>
      </header>

      <main className="flex-1 max-w-5xl w-full mx-auto p-4 md:p-6 mb-24 overflow-x-hidden">
        {activeTab === 'dashboard' && <Dashboard profile={profile} expenses={expenses} onAddExpense={addExpense} onNavigateToTab={(tab) => setActiveTab(tab)} isDarkMode={isDarkMode} />}
        {activeTab === 'budget' && <BudgetDetails profile={profile} expenses={expenses} onDeleteExpense={deleteExpense} isDarkMode={isDarkMode} />}
        {activeTab === 'chat' && <AIChat profile={profile} expenses={expenses} goals={goals} onUpdateGoals={updateGoals} isDarkMode={isDarkMode} />}
        {activeTab === 'academy' && <Academy profile={profile} onUpdateProfile={handleUpdateProfile} onCompleteLesson={completeLesson} isDarkMode={isDarkMode} />}
        {activeTab === 'social' && <Social profile={profile} onUpdateProfile={handleUpdateProfile} isDarkMode={isDarkMode} />}
        {activeTab === 'profile' && <ProfilePage profile={profile} expenses={expenses} onUpdateProfile={handleUpdateProfile} isDarkMode={isDarkMode} onLogout={logout} onNavigateToTab={setActiveTab} />}
      </main>

      <nav className={`fixed bottom-0 left-0 right-0 border-t p-2 md:p-4 z-40 transition-colors backdrop-blur-md ${isDarkMode ? 'bg-slate-900/80 border-slate-800' : 'bg-white/80 border-slate-100'}`}>
        <div className="max-w-xl mx-auto flex justify-around items-center">
          <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z" /></svg>} label="Inicio" />
          <NavButton active={activeTab === 'budget'} onClick={() => setActiveTab('budget')} icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 3.055A9.001 9.001 0 1020.945 13H11V3.055z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.488 9H15V3.512A9.025 9.025 0 0120.488 9z" /></svg>} label="Plan" />
          <NavButton active={activeTab === 'academy'} onClick={() => setActiveTab('academy')} icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>} label="Cursos" />
          <NavButton active={activeTab === 'social'} onClick={() => setActiveTab('social')} icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>} label="Social" />
          <NavButton active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={<svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM4.5 18a8.5 8.5 0 0115 0" /></svg>} label="Perfil" />
        </div>
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
