const Academy: React.FC<{ 
  profile: UserProfile, 
  onUpdateProfile: (u: Partial<UserProfile>) => void, 
  onCompleteLesson: (id: string, xp: number) => void, 
  isDarkMode: boolean 
}> = ({ profile, onUpdateProfile, onCompleteLesson, isDarkMode }) => {
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);
  const [currentStepIdx, setCurrentStepIdx] = useState(0);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [stepFeedback, setStepFeedback] = useState<{ isCorrect: boolean, message: string } | null>(null);
  const [timer, setTimer] = useState(30);
  const [accumulatedXP, setAccumulatedXP] = useState(0);
  const [isWatchingAd, setIsWatchingAd] = useState(false);
  const [regenCountDown, setRegenCountDown] = useState('');
  const timerRef = useRef<any>(null);

  const completedSet = new Set(profile.completedLessons);

  // Contador de regeneración visible
  useEffect(() => {
    if (profile.lives >= 5) {
      setRegenCountDown('Máximo');
      return;
    }
    const interval = setInterval(() => {
      const lastRegen = profile.lastLifeRegenTime ? new Date(profile.lastLifeRegenTime) : new Date();
      const nextRegen = new Date(lastRegen.getTime() + 30 * 60 * 1000);
      const now = new Date();
      const diff = nextRegen.getTime() - now.getTime();

      if (diff <= 0) {
        onUpdateProfile({ lives: Math.min(5, profile.lives + 1), lastLifeRegenTime: new Date().toISOString() });
      } else {
        const mins = Math.floor(diff / 60000);
        const secs = Math.floor((diff % 60000) / 1000);
        setRegenCountDown(`${mins}:${secs < 10 ? '0' : ''}${secs}`);
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [profile.lives, profile.lastLifeRegenTime]);

  const startLesson = (lesson: Lesson) => {
    if (profile.lives <= 0) return;
    setActiveLesson(lesson);
    setCurrentStepIdx(0);
    setSelectedOption(null);
    setStepFeedback(null);
    setTimer(30);
    setAccumulatedXP(0);
    startTimer();
  };

  const startTimer = () => {
    if (timerRef.current) clearInterval(timerRef.current);
    setTimer(30);
    timerRef.current = setInterval(() => {
      setTimer(t => (t > 0 ? t - 1 : 0));
    }, 1000);
  };

  const handleNextStep = () => {
    if (!activeLesson) return;
    if (currentStepIdx < activeLesson.steps.length - 1) {
      setCurrentStepIdx(currentStepIdx + 1);
      setSelectedOption(null);
      setStepFeedback(null);
      startTimer();
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
      const totalXP = activeLesson.xp + accumulatedXP;
      onCompleteLesson(activeLesson.id, totalXP);
      setActiveLesson(null);
    }
  };

  const handleAnswer = (idx: number) => {
    if (!activeLesson || stepFeedback) return;
    const step = activeLesson.steps[currentStepIdx];
    setSelectedOption(idx);

    if (idx === step.correctIndex) {
      const timeBonus = timer > 15 ? 20 : 10;
      setAccumulatedXP(prev => prev + timeBonus);
      setStepFeedback({ isCorrect: true, message: `¡Correcto! Bonus: +${timeBonus} XP` });
      setTimeout(handleNextStep, 1500);
    } else {
      setStepFeedback({ isCorrect: false, message: '¡Error! Pierdes 1 vida.' });
      onUpdateProfile({ lives: Math.max(0, profile.lives - 1) });
      if (profile.lives <= 1) {
        setTimeout(() => setActiveLesson(null), 2000);
      }
    }
  };

  const simulateAd = () => {
    setIsWatchingAd(true);
    setTimeout(() => {
      onUpdateProfile({ lives: Math.min(5, profile.lives + 1) });
      setIsWatchingAd(false);
    }, 3000);
  };

  const renderMap = () => {
    return (
      <div className="relative flex flex-col items-center gap-24 py-24 px-4 overflow-hidden">
        <svg className="absolute top-0 left-1/2 -translate-x-1/2 w-64 h-full pointer-events-none opacity-10" viewBox="0 0 100 2500" preserveAspectRatio="none">
          <path d="M50,0 Q80,200 50,400 T50,800 Q20,1000 50,1200 T50,1600 Q80,1800 50,2000" fill="none" stroke={isDarkMode ? "#6366f1" : "#4f46e5"} strokeWidth="3" strokeDasharray="12 12" />
        </svg>

        {INVESTMENT_MAP.map((lesson, idx) => {
          const isCompleted = completedSet.has(lesson.id);
          const isUnlocked = idx === 0 || completedSet.has(INVESTMENT_MAP[idx - 1].id);
          const isCurrent = isUnlocked && !isCompleted;
          const offset = idx % 2 === 0 ? '-translate-x-14 md:-translate-x-20' : 'translate-x-14 md:translate-x-20';

          return (
            <div key={lesson.id} className={`relative z-10 flex flex-col items-center group transition-all duration-700 ${offset}`}>
               {(idx === 0 || INVESTMENT_MAP[idx-1].world !== lesson.world) && (
                 <div className="absolute -top-16 left-1/2 -translate-x-1/2 whitespace-nowrap">
                   <div className="flex flex-col items-center gap-1">
                     <span className="bg-indigo-600 text-white text-[8px] font-black uppercase tracking-[0.3em] px-5 py-2 rounded-full shadow-2xl border border-white/20">Mundo: {lesson.world}</span>
                     <div className="w-0.5 h-6 bg-indigo-500/30" />
                   </div>
                 </div>
               )}
              <button
                disabled={!isUnlocked || profile.lives <= 0}
                onClick={() => startLesson(lesson)}
                className={`w-28 h-28 rounded-[2.5rem] border-4 flex items-center justify-center text-5xl transition-all duration-500 shadow-2xl relative ${
                  isCompleted ? 'bg-emerald-500 border-emerald-300 text-white rotate-12' : isCurrent ? 'bg-indigo-600 border-indigo-400 text-white animate-bounce ring-8 ring-indigo-500/20' : isUnlocked ? 'bg-white border-slate-200 text-slate-800 dark:bg-slate-800 dark:border-slate-700' : 'bg-slate-100 border-slate-200 text-slate-300 dark:bg-slate-900 dark:border-slate-800 grayscale'
                }`}
              >
                {isUnlocked ? (isCompleted ? '🏆' : lesson.icon) : '🔒'}
              </button>
              <div className={`mt-4 text-center transition-all ${isUnlocked ? 'opacity-100 scale-100' : 'opacity-40 scale-90'}`}>
                <h4 className="font-black italic uppercase text-xs tracking-tight">{lesson.title}</h4>
                <span className="text-indigo-500 text-[10px] font-black">{lesson.xp} XP</span>
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className={`space-y-8 pb-32 min-h-screen transition-all duration-700 ${isDarkMode ? 'bg-slate-950' : 'bg-slate-50'}`}>
      <header className="px-6 py-10 flex items-center justify-between sticky top-0 z-50 backdrop-blur-xl bg-white/5 border-b border-white/5">
        <div>
          <h2 className="text-4xl font-black italic uppercase tracking-tighter bg-gradient-to-r from-indigo-500 to-emerald-500 bg-clip-text text-transparent">Academy</h2>
          <div className="flex items-center gap-2 mt-1">
            <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse" />
            <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Siguiente vida en: {regenCountDown}</p>
          </div>
        </div>
        <div className="flex items-center gap-4 bg-white/80 dark:bg-slate-900/80 px-4 py-3 rounded-full border border-white/10 shadow-2xl">
          <div className="flex items-center gap-2">
            <span className="text-rose-500 text-xl">❤️</span>
            <span className="font-black text-xl">{profile.lives}</span>
          </div>
          {profile.lives < 5 && (
            <button onClick={simulateAd} disabled={isWatchingAd} className="bg-indigo-600 text-white p-1 rounded-full hover:bg-indigo-700 disabled:opacity-50">
              {isWatchingAd ? '...' : '+'}
            </button>
          )}
        </div>
      </header>

      {profile.lives <= 0 && (
        <div className="mx-6 p-6 bg-rose-500/10 border-2 border-rose-500 rounded-[2rem] text-center animate-in zoom-in">
          <p className="text-3xl mb-2">💔</p>
          <h3 className="text-xl font-black uppercase italic mb-2">¡Sin Vidas!</h3>
          <p className="text-sm font-bold text-slate-500 mb-6 uppercase">Espera a que se recarguen o mira un anuncio para jugar ahora.</p>
          <button onClick={simulateAd} className="w-full bg-rose-500 text-white py-4 rounded-2xl font-black uppercase shadow-lg">Ver Anuncio (+1 Vida)</button>
        </div>
      )}

      {renderMap()}

      {activeLesson && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-0 md:p-8 bg-slate-950/98 backdrop-blur-3xl animate-in fade-in duration-500">
          <div className={`w-full h-full md:h-auto max-w-3xl md:rounded-[4rem] overflow-hidden flex flex-col shadow-2xl relative ${isDarkMode ? 'bg-slate-900' : 'bg-white'}`}>
            <div className="h-3 w-full bg-slate-100 dark:bg-slate-800"><div className="h-full bg-gradient-to-r from-indigo-600 to-emerald-500 transition-all duration-700 ease-out" style={{ width: `${((currentStepIdx + 1) / activeLesson.steps.length) * 100}%` }} /></div>
            <button onClick={() => setActiveLesson(null)} className="absolute top-8 right-8 p-4 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full z-10 transition-all"><svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg></button>
            <div className="flex-1 p-10 md:p-16 overflow-y-auto flex flex-col items-center text-center">
              <div className="mb-10 flex justify-between items-center w-full"><span className="text-[11px] font-black uppercase tracking-[0.4em] text-indigo-500 bg-indigo-500/10 px-4 py-1.5 rounded-full">Paso {currentStepIdx + 1} / {activeLesson.steps.length}</span><div className={`w-14 h-14 rounded-full border-4 flex items-center justify-center font-black text-lg ${timer < 10 ? 'border-rose-500 text-rose-500 animate-pulse' : 'border-indigo-500 text-indigo-500'}`}>{timer}</div></div>
              <div className="flex-1 space-y-10 w-full max-w-lg">
                <div className="text-8xl bg-slate-100 dark:bg-slate-800 p-8 rounded-[3rem] inline-block shadow-inner">{activeLesson.icon}</div>
                <h3 className="text-3xl md:text-5xl font-black italic uppercase leading-tight tracking-tighter">{activeLesson.steps[currentStepIdx].title}</h3>
                <p className="text-xl md:text-2xl leading-relaxed text-slate-600 dark:text-slate-300 font-medium">{activeLesson.steps[currentStepIdx].content}</p>
                {activeLesson.steps[currentStepIdx].type === 'info' && <button onClick={handleNextStep} className="w-full mt-12 bg-indigo-600 text-white py-6 rounded-[2rem] font-black uppercase tracking-widest shadow-2xl hover:bg-indigo-700 transition-all">Entendido</button>}
                {activeLesson.steps[currentStepIdx].type === 'quiz' && (
                  <div className="space-y-5 pt-8 w-full">
                    <p className="text-lg font-black uppercase text-indigo-500 tracking-tight">{activeLesson.steps[currentStepIdx].question}</p>
                    <div className="grid grid-cols-1 gap-4">
                      {activeLesson.steps[currentStepIdx].options?.map((opt, i) => (
                        <button key={i} disabled={!!stepFeedback} onClick={() => handleAnswer(i)} className={`w-full p-6 text-left rounded-[1.5rem] border-3 font-bold text-lg transition-all flex justify-between items-center ${selectedOption === i ? (i === activeLesson.steps[currentStepIdx].correctIndex ? 'bg-emerald-500 border-emerald-400 text-white shadow-emerald-500/40' : 'bg-rose-500 border-rose-400 text-white shadow-rose-500/40') : isDarkMode ? 'bg-slate-800 border-slate-700 hover:border-indigo-500' : 'bg-slate-50 border-slate-200 hover:border-indigo-400'} shadow-lg`}>
                          {opt}
                          {selectedOption === i && <span className="text-2xl">{i === activeLesson.steps[currentStepIdx].correctIndex ? '✓' : '✗'}</span>}
                        </button>
                      ))}
                    </div>
                  </div>
                )}
                {stepFeedback && <div className={`p-6 rounded-[2rem] border-3 animate-bounce mt-10 shadow-2xl ${stepFeedback.isCorrect ? 'bg-emerald-500/10 border-emerald-500 text-emerald-600' : 'bg-rose-500/10 border-rose-500 text-rose-600'}`}><p className="font-black text-xl uppercase tracking-tighter">{stepFeedback.isCorrect ? '¡Impresionante!' : '¡Analiza de nuevo!'}</p><p className="text-sm font-bold opacity-80 mt-1">{stepFeedback.message}</p></div>}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Academy;

import React, { useState, useEffect } from 'react';
import { UserProfile, Expense, Category, Frequency } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { CATEGORY_COLORS, CURRENCY_SYMBOLS, FREQUENCY_LABELS } from '../constants';
import FinancialSummary from './FinancialSummary';

interface DashboardProps {
  profile: UserProfile;
  expenses: Expense[];
  onAddExpense: (amount: number, category: Category, description: string, isFixed: boolean, frequency?: Frequency) => void;
  onNavigateToTab: (tab: 'budget') => void;
  isDarkMode: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ profile, expenses, onAddExpense, onNavigateToTab, isDarkMode }) => {
  const [selectedCat, setSelectedCat] = useState<Category>(Category.NEEDS);
  const [timeRemainingToday, setTimeRemainingToday] = useState<string>('');
  const [dayProgressPercent, setDayProgressPercent] = useState(100);
  const [showSummary, setShowSummary] = useState(false);

  const currencySymbol = CURRENCY_SYMBOLS[profile.currency] || '$';

  // Lógica de ciclo financiero ajustada a frecuencia
  const getCycleStart = () => {
    const d = new Date();
    if (profile.frequency === Frequency.WEEKLY) {
      d.setDate(d.getDate() - d.getDay()); // Inicio de semana (Domingo)
    } else if (profile.frequency === Frequency.BIWEEKLY) {
      d.setDate(d.getDate() > 15 ? 16 : 1); // Quincena
    } else {
      d.setDate(1); // Mes
    }
    d.setHours(0,0,0,0);
    return d;
  };

  const cycleStart = getCycleStart();
  const currentCycleExpenses = expenses.filter(e => new Date(e.date) >= cycleStart);
  const totalCycleExpenses = currentCycleExpenses.reduce((acc, curr) => acc + curr.amount, 0);
  const balance = profile.income - totalCycleExpenses;

  useEffect(() => {
    const updateDailyCountdown = () => {
      const now = new Date();
      const midnight = new Date();
      midnight.setHours(24, 0, 0, 0);
      const diffMs = midnight.getTime() - now.getTime();
      const hours = Math.floor(diffMs / (1000 * 60 * 60));
      const minutes = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));
      setTimeRemainingToday(`${hours}h ${minutes}m`);
      setDayProgressPercent((diffMs / (24 * 60 * 60 * 1000)) * 100);
    };
    updateDailyCountdown();
    const timer = setInterval(updateDailyCountdown, 30000);
    return () => clearInterval(timer);
  }, []);

  const getCategoryTotal = (cat: Category) => 
    currentCycleExpenses.filter(e => e.category === cat).reduce((acc, curr) => acc + curr.amount, 0);

  const chartData = [
    { name: 'Necesidades', value: getCategoryTotal(Category.NEEDS), color: CATEGORY_COLORS.NEEDS },
    { name: 'Deseos', value: getCategoryTotal(Category.WANTS), color: CATEGORY_COLORS.WANTS },
    { name: 'Ahorro', value: getCategoryTotal(Category.SAVINGS), color: CATEGORY_COLORS.SAVINGS },
  ].filter(d => d.value > 0);

  const periodLabel = FREQUENCY_LABELS[profile.frequency];

  const todayDate = new Date();
  todayDate.setHours(0, 0, 0, 0);
  const streakAchievedToday = profile.lastStreakDate && new Date(profile.lastStreakDate).getTime() === todayDate.getTime();

  return (
    <div className="space-y-6 animate-in fade-in duration-500 overflow-x-hidden">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className={`p-6 rounded-3xl border shadow-sm flex flex-col justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
          <div className="flex justify-between items-start">
            <span className="text-slate-500 text-sm font-medium uppercase tracking-wider">Balance {periodLabel}</span>
            <button onClick={() => setShowSummary(true)} className="p-1 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg text-indigo-500">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M2 11a1 1 0 011-1h2a1 1 0 011 1v5a1 1 0 01-1 1H3a1 1 0 01-1-1v-5zM8 7a1 1 0 011-1h2a1 1 0 011 1v9a1 1 0 01-1 1H9a1 1 0 01-1-1V7zM14 4a1 1 0 011-1h2a1 1 0 011 1v12a1 1 0 01-1 1h-2a1 1 0 01-1-1V4z" /></svg>
            </button>
          </div>
          <div className="flex items-end gap-2 mt-2">
            <span className="text-3xl font-bold">{currencySymbol}{balance.toLocaleString()}</span>
            <span className={`text-xs font-black px-2 py-1 rounded-full ${balance >= 0 ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'}`}>{balance >= 0 ? 'Disponible' : 'Sobrepasado'}</span>
          </div>
        </div>

        <div className={`relative p-6 rounded-3xl border shadow-sm flex flex-col justify-between transition-all overflow-hidden ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
