          <div className="flex items-center gap-3 mt-2"><div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all duration-500 ${streakAchievedToday ? 'bg-orange-500 text-white shadow-[0_0_20px_rgba(249,115,22,0.5)] animate-pulse' : (isDarkMode ? 'bg-slate-800 text-slate-600 grayscale' : 'bg-slate-100 text-slate-400 grayscale')}`}><span className={`text-2xl ${streakAchievedToday ? 'scale-110' : 'scale-100'}`}>🔥</span></div><div><span className={`text-2xl font-black italic ${streakAchievedToday ? (isDarkMode ? 'text-white' : 'text-slate-900') : 'text-slate-400'}`}>{profile.streak} Días</span><p className={`text-[9px] font-black uppercase tracking-widest ${streakAchievedToday ? 'text-emerald-500' : 'text-slate-400'}`}>{streakAchievedToday ? 'Racha Protegida ✓' : '¡Regístra algo o estudia!'}</p></div></div>
        </div>

        <div className={`p-6 rounded-3xl border shadow-sm flex flex-col justify-between transition-colors ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}><span className="text-slate-500 text-sm font-medium uppercase tracking-wider">Gastos {periodLabel}</span><span className="text-3xl font-bold text-rose-500 mt-2">{currencySymbol}{totalCycleExpenses.toLocaleString()}</span></div>
